export interface Transcription {
  id: string;
  role: 'user' | 'assistant';
  text: string;
  timestamp: number;
}

export enum ConnectionStatus {
  DISCONNECTED = 'DISCONNECTED',
  CONNECTING = 'CONNECTING',
  CONNECTED = 'CONNECTED',
  ERROR = 'ERROR'
}

export function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useEffect, useRef } from 'react';

interface VisualizerProps {
  isActive: boolean;
  isSpeaking: boolean;
}

export const Visualizer: React.FC<VisualizerProps> = ({ isActive, isSpeaking }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (!canvasRef.current || !isActive) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationId: number;
    const barCount = 40;
    const bars = Array.from({ length: barCount }, () => Math.random());

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const width = canvas.width;
      const height = canvas.height;
      const barWidth = width / barCount;

      bars.forEach((val, i) => {
        const factor = isSpeaking ? 1.5 : (isActive ? 0.6 : 0.1);
        const barHeight = (Math.sin(Date.now() / 200 + i * 0.5) * 0.5 + 0.5) * height * 0.6 * factor;

        const x = i * barWidth;
        const y = (height - barHeight) / 2;

        const gradient = ctx.createLinearGradient(x, y, x, y + barHeight);
        gradient.addColorStop(0, '#2dd4bf'); // teal-400
        gradient.addColorStop(1, '#3b82f6'); // blue-500

        ctx.fillStyle = gradient;
        ctx.beginPath();
        ctx.roundRect(x + 2, y, barWidth - 4, barHeight, 4);
        ctx.fill();
      });

      animationId = requestAnimationFrame(draw);
    };

    draw();
    return () => cancelAnimationFrame(animationId);
  }, [isActive, isSpeaking]);

  return (
    <div className="relative w-full h-32 flex items-center justify-center overflow-hidden">
      <canvas 
        ref={canvasRef} 
        width={600} 
        height={128} 
        className="max-w-full"
      />
      {!isActive && (
        <div className="absolute inset-0 flex items-center justify-center text-slate-500 text-sm">
          انقر على الميكروفون للبدء
        </div>
      )}
    </div>
  );
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { ConnectionStatus, Transcription } from './types';
import { encode, decode, decodeAudioData } from './services/audioUtils';
import { Visualizer } from './components/Visualizer';

const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-12-2025';
const SYSTEM_INSTRUCTION = 'أنت مساعد صوتي ذكي وودود تدعى "سافيو". تحدث باللغة العربية بطلاقة بلهجة واضحة (لهجة بيضاء). كن مفيداً، ذكياً، وسريع الاستجابة. استمع جيداً وقدم إجابات مختصرة ومفيدة كما تفعل الأدوات الصوتية المتقدمة.';

const App: React.FC = () => {
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [transcriptions, setTranscriptions] = useState<Transcription[]>([]);
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);

  // Audio contexts
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const activeSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const sessionRef = useRef<any>(null);

  // Buffer transcriptions locally
  const currentInputTransRef = useRef('');
  const currentOutputTransRef = useRef('');

  const stopAllAudio = () => {
    activeSourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    activeSourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setIsAiSpeaking(false);
  };

  const handleStart = async () => {
    if (status !== ConnectionStatus.DISCONNECTED) return;

    setStatus(ConnectionStatus.CONNECTING);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Initialize Audio Contexts
      inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;

      const sessionPromise = ai.live.connect({
        model: MODEL_NAME,
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);

            const source = inputAudioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContextRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (event) => {
              const inputData = event.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }

              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then((session) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Transcription
            if (message.serverContent?.outputTranscription) {
              currentOutputTransRef.current += message.serverContent.outputTranscription.text;
            } else if (message.serverContent?.inputTranscription) {
              currentInputTransRef.current += message.serverContent.inputTranscription.text;
            }

            if (message.serverContent?.turnComplete) {
              const userText = currentInputTransRef.current.trim();
              const aiText = currentOutputTransRef.current.trim();

              if (userText) {
                setTranscriptions(prev => [...prev, { id: Date.now().toString(), role: 'user', text: userText, timestamp: Date.now() }]);
              }
              if (aiText) {
                setTranscriptions(prev => [...prev, { id: (Date.now() + 1).toString(), role: 'assistant', text: aiText, timestamp: Date.now() }]);
              }

              currentInputTransRef.current = '';
              currentOutputTransRef.current = '';
            }

            // Handle Audio Data
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputAudioContextRef.current) {
              setIsAiSpeaking(true);
              const ctx = outputAudioContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);

              source.onended = () => {
                activeSourcesRef.current.delete(source);
                if (activeSourcesRef.current.size === 0) {
                  setIsAiSpeaking(false);
                }
              };

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              activeSourcesRef.current.add(source);
            }

            // Handle Interruption
            if (message.serverContent?.interrupted) {
              stopAllAudio();
            }
          },
          onerror: (err) => {
            console.error('Gemini error:', err);
            setStatus(ConnectionStatus.ERROR);
          },
          onclose: () => {
            handleStop();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          systemInstruction: SYSTEM_INSTRUCTION,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });

      sessionRef.current = await sessionPromise;

    } catch (err) {
      console.error('Failed to start session:', err);
      setStatus(ConnectionStatus.ERROR);
    }
  };

  const handleStop = () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch (e) {}
    }

    stopAllAudio();

    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
    }

    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    if (outputAudioContextRef.current) outputAudioContextRef.current.close();

    sessionRef.current = null;
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const toggleConnection = () => {
    if (status === ConnectionStatus.DISCONNECTED) {
      handleStart();
    } else {
      handleStop();
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col items-center p-4 md:p-8">
      {/* Header */}
      <header className="w-full max-w-4xl flex items-center justify-between mb-12">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-teal-500 rounded-xl flex items-center justify-center shadow-lg shadow-teal-500/20">
            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          </div>
          <h1 className="text-2xl font-bold font-cairo bg-clip-text text-transparent bg-gradient-to-r from-teal-400 to-blue-400">
            سافيو العربي
          </h1>
        </div>
        <div className="text-sm text-slate-400 hidden md:block">
          نسخة صوتية ذكية مدعومة بتقنية Gemini Live
        </div>
      </header>

      {/* Main Interaction Area */}
      <main className="w-full max-w-2xl bg-slate-800/50 rounded-3xl p-8 border border-slate-700 backdrop-blur-sm shadow-2xl relative overflow-hidden">

        <Visualizer 
          isActive={status === ConnectionStatus.CONNECTED} 
          isSpeaking={isAiSpeaking} 
        />

        <div className="mt-8 flex flex-col items-center">
          <button
            onClick={toggleConnection}
            disabled={status === ConnectionStatus.CONNECTING}
            className={`w-24 h-24 rounded-full flex items-center justify-center transition-all duration-300 transform active:scale-95 shadow-2xl ${
              status === ConnectionStatus.CONNECTED 
                ? 'bg-red-500 hover:bg-red-600 ring-4 ring-red-500/20' 
                : 'bg-teal-500 hover:bg-teal-600 ring-4 ring-teal-500/20'
            } ${status === ConnectionStatus.CONNECTING ? 'animate-pulse opacity-50 cursor-not-allowed' : ''}`}
          >
            {status === ConnectionStatus.CONNECTED ? (
              <svg className="w-10 h-10 text-white" fill="currentColor" viewBox="0 0 20 20">
                <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1-1H7a1 1 0 00-1 1v6a1 1 0 001 1h1a1 1 0 001-1V7zM14 7a1 1 0 00-1-1h-1a1 1 0 00-1 1v6a1 1 0 001 1h1a1 1 0 001-1V7z" clipRule="evenodd" />
              </svg>
            ) : (
              <svg className="w-10 h-10 text-white" fill="currentColor" viewBox="0 0 20 20">
                <path fillRule="evenodd" d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 006 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z" clipRule="evenodd" />
              </svg>
            )}
          </button>

          <div className="mt-4 text-center">
            <p className="text-slate-300 font-medium">
              {status === ConnectionStatus.CONNECTED ? 'جاري الاستماع...' : 
               status === ConnectionStatus.CONNECTING ? 'جاري الاتصال...' : 
               status === ConnectionStatus.ERROR ? 'حدث خطأ في الاتصال' : 'ابدأ المحادثة الآن'}
            </p>
            {status === ConnectionStatus.CONNECTED && (
               <p className="text-xs text-teal-400 mt-1 animate-pulse">متصل ومستعد للإجابة</p>
            )}
          </div>
        </div>

        {/* Transcription History */}
        <div className="mt-12 w-full max-h-60 overflow-y-auto pr-2 space-y-4 custom-scrollbar">
          {transcriptions.length === 0 ? (
            <div className="text-center py-8">
              <p className="text-slate-500 italic text-sm">لا توجد رسائل سابقة. جرب قول "مرحباً سافيو!"</p>
            </div>
          ) : (
            transcriptions.slice().reverse().map((t) => (
              <div 
                key={t.id} 
                className={`flex flex-col ${t.role === 'user' ? 'items-start' : 'items-end'}`}
              >
                <div 
                  className={`max-w-[85%] p-3 rounded-2xl text-sm ${
                    t.role === 'user' 
                      ? 'bg-slate-700 text-slate-200 rounded-tr-none' 
                      : 'bg-teal-500/20 border border-teal-500/30 text-teal-100 rounded-tl-none'
                  }`}
                >
                  {t.text}
                </div>
                <span className="text-[10px] text-slate-500 mt-1 px-1">
                  {t.role === 'user' ? 'أنت' : 'سافيو'}
                </span>
              </div>
            ))
          )}
        </div>
      </main>

      {/* Footer / Instructions */}
      <footer className="mt-auto w-full max-w-4xl grid grid-cols-1 md:grid-cols-3 gap-6 py-8">
        <div className="bg-slate-800/30 p-4 rounded-2xl border border-slate-700/50">
          <div className="text-teal-400 mb-2">
