        sessionRef.current?.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } });
      };
      source.connect(scriptProcessor);
      scriptProcessor.connect(inputAudioContextRef.current!.destination);

    } catch (err) {
      console.error(err);
      setStatus(ConnectionStatus.ERROR);
    }
  };

  const playAudioChunk = async (base64: string) => {
    if (!outputAudioContextRef.current) {
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const ctx = outputAudioContextRef.current;
    setIsAiSpeaking(true);
    nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
    const audioBuffer = await decodeAudioData(decode(base64), ctx, 24000, 1);
    const source = ctx.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(ctx.destination);
    source.onended = () => {
      activeSourcesRef.current.delete(source);
      if (activeSourcesRef.current.size === 0) setIsAiSpeaking(false);
    };
    source.start(nextStartTimeRef.current);
    nextStartTimeRef.current += audioBuffer.duration;
    activeSourcesRef.current.add(source);
  };

  const handleStopLive = () => {
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}
    stopAllAudio();
    if (mediaStreamRef.current) mediaStreamRef.current.getTracks().forEach(track => track.stop());
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    sessionRef.current = null;
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const generateTTS = async () => {
    if (!ttsText.trim() || isGeneratingTts) return;
    setIsGeneratingTts(true);
    stopAllAudio();

    try {
      const moodPrefix = MOOD_OPTIONS.find(m => m.id === selectedMood)?.prompt || '';
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: TTS_MODEL,
        contents: [{ parts: [{ text: `${moodPrefix}${ttsText}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: selectedVoice } } },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        await playAudioChunk(base64Audio);
      }
    } catch (err) {
      console.error('TTS Generation error:', err);
    } finally {
      setIsGeneratingTts(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col items-center p-4 md:p-8">
      {/* Header */}
      <header className="w-full max-w-4xl flex flex-col md:flex-row items-center justify-between mb-8 gap-4">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-teal-500 rounded-2xl flex items-center justify-center shadow-lg shadow-teal-500/20">
            <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          </div>
          <div>
            <h1 className="text-2xl font-bold font-cairo bg-clip-text text-transparent bg-gradient-to-r from-teal-400 to-blue-400">
              سافيو الصوتي
            </h1>
            <p className="text-xs text-slate-400">الجيل القادم من تحويل النص والمحادثة</p>
          </div>
        </div>

        {/* Mode Switcher */}
        <div className="bg-slate-800 p-1 rounded-xl border border-slate-700 flex">
          <button 
            onClick={() => { setMode('live'); handleStopLive(); }}
            className={`px-4 py-2 rounded-lg text-sm transition-all ${mode === 'live' ? 'bg-teal-500 text-white shadow-md' : 'text-slate-400 hover:text-slate-200'}`}
          >
            محادثة مباشرة
          </button>
          <button 
            onClick={() => { setMode('tts'); handleStopLive(); }}
            className={`px-4 py-2 rounded-lg text-sm transition-all ${mode === 'tts' ? 'bg-teal-500 text-white shadow-md' : 'text-slate-400 hover:text-slate-200'}`}
          >
            تحويل النص لصوت
          </button>
        </div>
      </header>

      <div className="w-full max-w-5xl grid grid-cols-1 lg:grid-cols-12 gap-6">

        {/* Left Column: Main Interface */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <main className="bg-slate-800/50 rounded-3xl p-6 border border-slate-700 backdrop-blur-sm shadow-2xl min-h-[400px] flex flex-col">

            {mode === 'live' ? (
              <div className="flex-1 flex flex-col">
                <Visualizer isActive={status === ConnectionStatus.CONNECTED} isSpeaking={isAiSpeaking} />

                <div className="mt-8 flex flex-col items-center flex-1 justify-center">
                  <button
                    onClick={status === ConnectionStatus.CONNECTED ? handleStopLive : handleStartLive}
                    disabled={status === ConnectionStatus.CONNECTING}
                    className={`w-28 h-28 rounded-full flex items-center justify-center transition-all duration-300 transform active:scale-95 shadow-2xl ${
                      status === ConnectionStatus.CONNECTED ? 'bg-red-500 hover:bg-red-600' : 'bg-teal-500 hover:bg-teal-600'
                    } ${status === ConnectionStatus.CONNECTING ? 'animate-pulse opacity-50' : ''}`}
                  >
                    {status === ConnectionStatus.CONNECTED ? (
                      <svg className="w-12 h-12 text-white" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1-1H7a1 1 0 00-1 1v6a1 1 0 001 1h1a1 1 0 001-1V7zM14 7a1 1 0 00-1-1h-1a1 1 0 00-1 1v6a1 1 0 001 1h1a1 1 0 001-1V7z"/></svg>
                    ) : (
                      <svg className="w-12 h-12 text-white" fill="currentColor" viewBox="0 0 20 20"><path d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 006 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z"/></svg>
                    )}
                  </button>
                  <p className="mt-4 text-slate-300 font-medium">
                    {status === ConnectionStatus.CONNECTED ? 'سافيو يستمع إليك...' : 'اضغط للبدء في التحدث مع سافيو'}
                  </p>
                </div>

                <div className="mt-6 max-h-40 overflow-y-auto space-y-3 custom-scrollbar px-2">
                  {transcriptions.slice().reverse().map(t => (
                    <div key={t.id} className={`flex ${t.role === 'user' ? 'justify-start' : 'justify-end'}`}>
                      <div className={`p-2 rounded-xl text-xs max-w-[80%] ${t.role === 'user' ? 'bg-slate-700' : 'bg-teal-900/40 border border-teal-500/30'}`}>
                        {t.text}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            ) : (
              <div className="flex-1 flex flex-col">
                <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                  <svg className="w-5 h-5 text-teal-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                  اكتب النص لتحويله لصوت
                </h2>
                <textarea
                  value={ttsText}
                  onChange={(e) => setTtsText(e.target.value)}
                  placeholder="اكتب هنا النص الذي ترغب في سماعه بصوت سافيو..."
                  className="flex-1 bg-slate-900/80 border border-slate-700 rounded-2xl p-4 text-slate-200 focus:ring-2 focus:ring-teal-500 outline-none resize-none transition-all placeholder:text-slate-600"
                />
                <div className="mt-6 flex justify-between items-center">
                  <div className="flex items-center gap-2">
                    {isGeneratingTts && (
                      <div className="flex items-center gap-2 text-teal-400 text-sm">
                        <div className="w-2 h-2 bg-teal-500 rounded-full animate-ping" />
                        جاري التوليد...
                      </div>
                    )}
                    {isAiSpeaking && !isGeneratingTts && (
                       <div className="flex items-center gap-1">
                         <div className="w-1 h-3 bg-teal-500 rounded-full animate-bounce" />
                         <div className="w-1 h-5 bg-teal-500 rounded-full animate-bounce [animation-delay:0.1s]" />
                         <div className="w-1 h-4 bg-teal-500 rounded-full animate-bounce [animation-delay:0.2s]" />
                       </div>
                    )}
                  </div>
                  <button
                    onClick={generateTTS}
                    disabled={!ttsText.trim() || isGeneratingTts}
                    className="bg-teal-500 hover:bg-teal-600 disabled:opacity-50 disabled:cursor-not-allowed text-white px-8 py-3 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2"
                  >
                    {isGeneratingTts ? 'انتظر...' : (
                      <>
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                        تحويل واستماع
                      </>
                    )}
                  </button>
                </div>
              </div>
            )}
          </main>
        </div>

        {/* Right Column: Settings Panel */}
        <aside className="lg:col-span-4 flex flex-col gap-6">
          <div className="bg-slate-800/80 rounded-3xl p-6 border border-slate-700 shadow-xl">
            <h3 className="text-lg font-bold mb-6 flex items-center gap-2 text-teal-400">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
              تخصيص الصوت
            </h3>

            <div className="space-y-6">
              {/* Voice Selector */}
              <div>
                <label className="text-xs text-slate-400 uppercase tracking-wider block mb-3">اختر الشخصية</label>
                <div className="grid grid-cols-1 gap-2">
                  {VOICE_OPTIONS.map((v) => (
                    <button
                      key={v.id}
                      onClick={() => setSelectedVoice(v.id)}
                      className={`text-right p-3 rounded-xl border transition-all ${
                        selectedVoice === v.id 
                          ? 'bg-teal-500/20 border-teal-500 text-teal-100' 
                          : 'bg-slate-900/50 border-slate-700 text-slate-400 hover:border-slate-600'
                      }`}
                    >
                      <div className="text-sm font-bold">{v.label}</div>
                      <div className="text-[10px] opacity-70">{v.desc}</div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Mood Selector */}
              <div>
                <label className="text-xs text-slate-400 uppercase tracking-wider block mb-3">نبرة الصوت (المشاعر)</label>
                <div className="grid grid-cols-2 gap-2">
                  {MOOD_OPTIONS.map((m) => (
                    <button
                      key={m.id}
                      onClick={() => setSelectedMood(m.id)}
                      className={`text-center py-2 px-3 rounded-lg text-xs border transition-all ${
                        selectedMood === m.id 
                          ? 'bg-blue-500/20 border-blue-500 text-blue-100' 
                          : 'bg-slate-900/50 border-slate-700 text-slate-400 hover:border-slate-600'
                      }`}
                    >
                      {m.label}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>

          <div className="bg-gradient-to-br from-indigo-500/20 to-teal-500/20 rounded-3xl p-5 border border-white/5">
            <h4 className="text-sm font-bold text-white mb-2">تلميحة ذكية 💡</h4>
            <p className="text-xs text-slate-400 leading-relaxed">
              يمكنك كتابة نصوص طويلة وتغيير "نبرة الصوت" للحصول على قراءات درامية أو إخبارية. جرب الصوت "العميق" مع النبرة "الجادة".
            </p>
          </div>
        </aside>

      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: rgba(15, 23, 42, 0.1); }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(45, 212, 191, 0.2); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { ConnectionStatus, Transcription } from './types';
import { encode, decode, decodeAudioData } from './services/audioUtils';
import { Visualizer } from './components/Visualizer';

const LIVE_MODEL = 'gemini-2.5-flash-native-audio-preview-12-2025';
const TTS_MODEL = 'gemini-2.5-flash-preview-tts';

type AppMode = 'live' | 'tts';
type VoiceType = 'Kore' | 'Puck' | 'Charon' | 'Fenrir' | 'Zephyr';

interface DialectOption {
  id: string;
  label: string;
  flag: string;
  instruction: string;
}

const DIALECT_OPTIONS: DialectOption[] = [
  { id: 'egyptian', label: 'مصري (عامية)', flag: '🇪🇬', instruction: 'تحدث باللهجة المصرية العامية بأسلوب ولاد البلد، خفيف الظل وسريع البديهة.' },
  { id: 'saudi_najdi', label: 'سعودي (نجدي)', flag: '🇸🇦', instruction: 'تحدث بلهجة أهل نجد (الرياض)، بأسلوب رزين، محترم وودود جداً.' },
  { id: 'khaleeji', label: 'خليجي (كويتي/إماراتي)', flag: '🇰🇼', instruction: 'تحدث بلهجة خليجية بيضاء واضحة، بأسلوب راقي وهادئ.' },
  { id: 'levantine', label: 'شامي (لبناني/سوري)', flag: '🇱🇧', instruction: 'تحدث بلهجة شامية محببة (لبنانية أو سورية)، بأسلوب لبق وناعم.' },
  { id: 'maghrebi', label: 'مغاربي (مبسط)', flag: '🇲🇦', instruction: 'تحدث بلهجة مغاربية بيضاء يفهمها الجميع، بأسلوب عصري.' },
  { id: 'fusha', label: 'عربية فصحى', flag: '📖', instruction: 'تحدث باللغة العربية الفصحى السليمة، بأسلوب إخباري وقور كالمذيعين.' },
];

const SPEED_OPTIONS = [
  { id: 'slow', label: 'بطيء', desc: 'تحدث ببطء شديد ووضوح تام مخارج الحروف.' },
  { id: 'normal', label: 'طبيعي', desc: '' },
  { id: 'fast', label: 'سريع', desc: 'تحدث بسرعة وحماس كأنك في موجز إخباري.' },
];

const MOOD_OPTIONS = [
  { id: 'cheerful', label: 'سعيد/مرح', prompt: 'بصوت مفعم بالفرح والسعادة: ' },
  { id: 'sad', label: 'حزين/هادئ', prompt: 'بصوت هادئ جداً، خافت، وفيه نبرة شجن: ' },
  { id: 'serious', label: 'رسمي/وقور', prompt: 'بصوت رسمي جداً، جاد، وبدون مشاعر زائدة: ' },
  { id: 'excited', label: 'متحمس للغاية', prompt: 'بصوت صاخب، حماسي جداً وكأنك تشجع في مباراة: ' },
  { id: 'whisper', label: 'همس', prompt: 'تحدث بصوت خفيض جداً كأنك تهمس في أذن شخص: ' },
  { id: 'neutral', label: 'طبيعي', prompt: '' },
];

const VOICE_OPTIONS = [
  { id: 'Kore', label: 'ليلى', desc: 'أنثوي ناعم' },
  { id: 'Puck', label: 'سلمى', desc: 'أنثوي حيوي' },
  { id: 'Charon', label: 'عمر', desc: 'رجولي وقور' },
  { id: 'Fenrir', label: 'زيد', desc: 'رجولي قوي' },
  { id: 'Zephyr', label: 'أمل', desc: 'شبابي مرح' },
];

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('live');
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [transcriptions, setTranscriptions] = useState<Transcription[]>([]);
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [isGeneratingTts, setIsGeneratingTts] = useState(false);

  // Advanced State
  const [ttsText, setTtsText] = useState('');
  const [selectedVoice, setSelectedVoice] = useState<VoiceType>('Kore');
  const [selectedDialect, setSelectedDialect] = useState(DIALECT_OPTIONS[0]);
  const [selectedMood, setSelectedMood] = useState(MOOD_OPTIONS[5]);
  const [selectedSpeed, setSelectedSpeed] = useState(SPEED_OPTIONS[1]);

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const activeSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const sessionRef = useRef<any>(null);

  const currentInputTransRef = useRef('');
  const currentOutputTransRef = useRef('');

  const stopAllAudio = () => {
    activeSourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
    activeSourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setIsAiSpeaking(false);
  };

  const buildSystemInstruction = () => {
    return `أنت مساعد صوتي ذكي تدعى "سافيو". 
            القاعدة الذهبية: ${selectedDialect.instruction}
            ${selectedSpeed.desc}
            حافظ على شخصيتك الودودة والذكية دائماً.`;
  };

  const handleStartLive = async () => {
    if (status !== ConnectionStatus.DISCONNECTED) return;
    setStatus(ConnectionStatus.CONNECTING);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;

      const sessionPromise = ai.live.connect({
        model: LIVE_MODEL,
        callbacks: {
          onopen: () => setStatus(ConnectionStatus.CONNECTED),
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) currentOutputTransRef.current += message.serverContent.outputTranscription.text;
            else if (message.serverContent?.inputTranscription) currentInputTransRef.current += message.serverContent.inputTranscription.text;

            if (message.serverContent?.turnComplete) {
              const uText = currentInputTransRef.current.trim();
              const aText = currentOutputTransRef.current.trim();
              if (uText) setTranscriptions(prev => [...prev, { id: Date.now().toString(), role: 'user', text: uText, timestamp: Date.now() }]);
              if (aText) setTranscriptions(prev => [...prev, { id: (Date.now() + 1).toString(), role: 'assistant', text: aText, timestamp: Date.now() }]);
              currentInputTransRef.current = '';
              currentOutputTransRef.current = '';
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) playAudioChunk(base64Audio);
            if (message.serverContent?.interrupted) stopAllAudio();
          },
          onerror: (err) => { setStatus(ConnectionStatus.ERROR); console.error(err); },
          onclose: () => handleStopLive()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: selectedVoice } } },
          systemInstruction: buildSystemInstruction(),
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });

      sessionRef.current = await sessionPromise;
      const source = inputAudioContextRef.current!.createMediaStreamSource(stream);
      const scriptProcessor = inputAudioContextRef.current!.createScriptProcessor(4096, 1, 1);
      scriptProcessor.onaudioprocess = (event) => {
        const inputData = event.inputBuffer.getChannelData(0);
        const int16 = new Int16Array(inputData.length);
        for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
        sessionRef.current?.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } });
      };
      source.connect(scriptProcessor);
      scriptProcessor.connect(inputAudioContextRef.current!.destination);
    } catch (err) { setStatus(ConnectionStatus.ERROR); }
  };

  const playAudioChunk = async (base64: string) => {
    if (!outputAudioContextRef.current) outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const ctx = outputAudioContextRef.current;
    setIsAiSpeaking(true);
    nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
    const audioBuffer = await decodeAudioData(decode(base64), ctx, 24000, 1);
    const source = ctx.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(ctx.destination);
    source.onended = () => {
      activeSourcesRef.current.delete(source);
      if (activeSourcesRef.current.size === 0) setIsAiSpeaking(false);
    };
    source.start(nextStartTimeRef.current);
    nextStartTimeRef.current += audioBuffer.duration;
    activeSourcesRef.current.add(source);
  };

  const handleStopLive = () => {
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}
    stopAllAudio();
    if (mediaStreamRef.current) mediaStreamRef.current.getTracks().forEach(track => track.stop());
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    sessionRef.current = null;
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const generateTTS = async () => {
    if (!ttsText.trim() || isGeneratingTts) return;
    setIsGeneratingTts(true);
    stopAllAudio();

    try {
      const fullPrompt = `${selectedDialect.instruction} ${selectedMood.prompt} ${selectedSpeed.desc} النص المطلوب قوله هو: "${ttsText}"`;
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: TTS_MODEL,
        contents: [{ parts: [{ text: fullPrompt }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: selectedVoice } } },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) await playAudioChunk(base64Audio);
    } catch (err) { console.error(err); } finally { setIsGeneratingTts(false); }
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 p-4 md:p-8 font-tajawal">
      <div className="max-w-6xl mx-auto flex flex-col gap-8">

