                      <div key={v.id} className="relative">
                        <button
                          onClick={() => !isLocked && setSelectedVoice(v.id as VoiceType)}
                          className={`w-full flex items-center justify-between p-4 rounded-[20px] border transition-all ${selectedVoice === v.id ? 'bg-purple-500/10 border-purple-500/50 text-purple-100 shadow-inner' : 'bg-slate-900/40 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                        >
