                          className={`absolute left-4 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full flex items-center justify-center transition-all ${isPreviewing === v.id ? 'bg-teal-500 text-white' : 'bg-slate-800 text-teal-400 hover:bg-slate-700 border border-slate-600 shadow-lg hover:scale-110'}`}
                          title="تجربة الصوت"
