              </div>

              {isLocked && (
                <div className="mt-4 p-4 bg-orange-500/10 rounded-2xl border border-orange-500/20 text-center">
                   <p className="text-[10px] text-orange-400 font-bold uppercase tracking-widest">الإعدادات مقفلة لضمان الاستمرارية</p>
                </div>
