      <style>{`
        .font-tajawal { font-family: 'Tajawal', sans-serif; }
        .font-cairo { font-family: 'Cairo', sans-serif; }
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(45, 212, 191, 0.15); border-radius: 20px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(45, 212, 191, 0.3); }
        .scrollbar-hide::-webkit-scrollbar { display: none; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { ConnectionStatus, Transcription } from './types';
import { encode, decode, decodeAudioData, audioBufferToWav } from './services/audioUtils';
import { Visualizer } from './components/Visualizer';

const LIVE_MODEL = 'gemini-2.5-flash-native-audio-preview-12-2025';
const TTS_MODEL = 'gemini-2.5-flash-preview-tts';

type AppMode = 'live' | 'tts';
type VoiceType = 'Kore' | 'Puck' | 'Charon' | 'Fenrir' | 'Zephyr';

