const TTS_MODEL = 'gemini-2.5-flash-preview-tts';

type AppMode = 'live' | 'tts';
type VoiceType = 'Kore' | 'Puck' | 'Charon' | 'Fenrir' | 'Zephyr';

interface DialectOption {
  id: string;
  label: string;
  flag: string;
  instruction: string;
}

const DIALECT_OPTIONS: DialectOption[] = [
  { id: 'egyptian', label: 'مصري (عامية)', flag: '🇪🇬', instruction: 'تحدث باللهجة المصرية العامية بأسلوب ولاد البلد، خفيف الظل وسريع البديهة.' },
  { id: 'saudi_najdi', label: 'سعودي (نجدي)', flag: '🇸🇦', instruction: 'تحدث بلهجة أهل نجد (الرياض)، بأسلوب رزين، محترم وودود جداً.' },
  { id: 'khaleeji', label: 'خليجي (كويتي/إماراتي)', flag: '🇰🇼', instruction: 'تحدث بلهجة خليجية بيضاء واضحة، بأسلوب راقي وهادئ.' },
  { id: 'levantine', label: 'شامي (لبناني/سوري)', flag: '🇱🇧', instruction: 'تحدث بلهجة شامية محببة (لبنانية أو سورية)، بأسلوب لبق وناعم.' },
  { id: 'maghrebi', label: 'مغاربي (مبسط)', flag: '🇲🇦', instruction: 'تحدث بلهجة مغاربية بيضاء يفهمها الجميع، بأسلوب عصري.' },
  { id: 'fusha', label: 'عربية فصحى', flag: '📖', instruction: 'تحدث باللغة العربية الفصحى السليمة، بأسلوب إخباري وقور كالمذيعين.' },
];

const PERSONA_OPTIONS = [
  { id: 'child', label: 'طفولي', icon: '👶', instruction: 'تقمص شخصية طفل صغير بريء، بمفردات بسيطة ونبرة مرحة ولطيفة.' },
  { id: 'youth', label: 'شبابي', icon: '⚡', instruction: 'تحدث بأسلوب شبابي عصري مفعم بالحيوية والطاقة العالية.' },
  { id: 'elder', label: 'وقور/حكيم', icon: '🧓', instruction: 'تحدث بصوت شخص كبير في السن، حكيم، هادئ، رزين ووقور جداً.' },
  { id: 'narrator', label: 'حكواتي', icon: '📚', instruction: 'تقمص دور الحكواتي أو الراوي، مع تلوين صوتي درامي وتشويق في الإلقاء.' },
  { id: 'doc', label: 'وثائقي', icon: '🎥', instruction: 'تحدث بأسلوب المعلقين في الأفلام الوثائقية، صوت رخيم، عميق، رصين ومعلوماتي.' },
  { id: 'action', label: 'أكشن', icon: '🔥', instruction: 'تحدث بأسلوب إعلانات أفلام الأكشن، نبرة قوية جداً، سريعة، ومثيرة للحماس.' },
  { id: 'anchor', label: 'مذيع أخبار', icon: '🎙️', instruction: 'تحدث بأسلوب مذيعي القنوات الإخبارية الكبرى، مخارج حروف واضحة ونبرة واثقة.' },
  { id: 'teacher', label: 'معلم', icon: '👨‍🏫', instruction: 'تحدث بأسلوب تعليمي، هادئ، يشرح بصبر ووضوح تام.' },
  { id: 'gamer', label: 'لاعب/Gamer', icon: '🎮', instruction: 'تحدث بأسلوب حماسي سريع، يستخدم مصطلحات الألعاب ومفعم بالطاقة.' },
  { id: 'cartoon', label: 'كرتون', icon: '🎈', instruction: 'تحدث بنبرة مبالغ فيها، مرحة جداً وشبيهة بشخصيات الرسوم المتحركة.' },
  { id: 'default', label: 'طبيعي', icon: '👤', instruction: 'تحدث بأسلوب مساعد ذكي طبيعي وودود.' },
];

const SPEED_OPTIONS = [
  { id: 'slow', label: 'بطيء', desc: 'تحدث ببطء شديد ووضوح تام لمخارج الحروف.' },
  { id: 'normal', label: 'طبيعي', desc: '' },
  { id: 'fast', label: 'سريع', desc: 'تحدث بسرعة وحماس.' },
];

const MOOD_OPTIONS = [
  { id: 'cheerful', label: 'سعيد/مرح', prompt: 'بصوت مفعم بالفرح والسعادة: ' },
  { id: 'sad', label: 'حزين/هادئ', prompt: 'بصوت هادئ جداً، خافت، وفيه نبرة شجن: ' },
  { id: 'serious', label: 'رسمي/وقور', prompt: 'بصوت رسمي جداً، جاد، وبدون مشاعر زائدة: ' },
  { id: 'excited', label: 'متحمس للغاية', prompt: 'بصوت صاخب وحماسي جداً: ' },
  { id: 'whisper', label: 'همس خافت', prompt: 'تحدث بصوت خفيض جداً كأنك تهمس في أذن شخص: ' },
  { id: 'neutral', label: 'طبيعي', prompt: '' },
];

const VOICE_OPTIONS = [
  { id: 'Kore', label: 'ليلى', desc: 'أنثوي ناعم' },
  { id: 'Puck', label: 'سلمى', desc: 'أنثوي حيوي' },
  { id: 'Charon', label: 'عمر', desc: 'رجولي وقور' },
  { id: 'Fenrir', label: 'زيد', desc: 'رجولي قوي' },
  { id: 'Zephyr', label: 'أمل', desc: 'شبابي مرح' },
];

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('live');
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [transcriptions, setTranscriptions] = useState<Transcription[]>([]);
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [isGeneratingTts, setIsGeneratingTts] = useState(false);
  const [isPreviewing, setIsPreviewing] = useState<string | null>(null);
  const [isEditMode, setIsEditMode] = useState(true);
  const [isLocked, setIsLocked] = useState(false);

  // Mimicry/Cloning state
  const [isRecordingReference, setIsRecordingReference] = useState(false);
  const [referenceAudio, setReferenceAudio] = useState<string | null>(null);

  // Advanced State
  const [ttsText, setTtsText] = useState('');
  const [selectedVoice, setSelectedVoice] = useState<VoiceType>('Kore');
  const [selectedDialect, setSelectedDialect] = useState(DIALECT_OPTIONS[0]);
  const [selectedMood, setSelectedMood] = useState(MOOD_OPTIONS[5]);
  const [selectedSpeed, setSelectedSpeed] = useState(SPEED_OPTIONS[1]);
  const [selectedPersona, setSelectedPersona] = useState(PERSONA_OPTIONS[10]);
  const [effectIntensity, setEffectIntensity] = useState(70); // 0 to 100

  const [lastAudioBuffer, setLastAudioBuffer] = useState<AudioBuffer | null>(null);

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const activeSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const sessionRef = useRef<any>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const currentInputTransRef = useRef('');
  const currentOutputTransRef = useRef('');

  const stopAllAudio = () => {
    activeSourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
    activeSourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setIsAiSpeaking(false);
  };

  const shareApp = async () => {
    const inviteLink = window.location.href;
    const shareData = {
      title: 'تطبيق هزاع AI - صوتك بالعربي',
      text: `تعال جرب تطبيق "هزاع"، أقوى مساعد صوتي بذكاء اصطناعي يدعم كل اللهجات العربية! ادخل من هذا الرابط وجربه الآن:`,
      url: inviteLink,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Error sharing', err);
      }
    } else {
      navigator.clipboard.writeText(`${shareData.text}\n${inviteLink}`);
      alert('تم نسخ رسالة الدعوة ورابط الدخول لمشاركتها مع أصدقائك!');
    }
  };

  const downloadAudio = () => {
    if (!lastAudioBuffer) return;
    // Note: Standard high-quality WAV is the best for high-quality audio needs. 
    // Converting to MP3 without heavy libraries in-browser is limited.
    const blob = audioBufferToWav(lastAudioBuffer);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Hazza_Studio_HD_${Date.now()}.wav`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const startRecordingReference = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;
      audioChunksRef.current = [];

      recorder.ondataavailable = (e) => audioChunksRef.current.push(e.data);
      recorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = () => {
          const base64data = reader.result as string;
          setReferenceAudio(base64data.split(',')[1]);
        };
        stream.getTracks().forEach(t => t.stop());
      };

      recorder.start();
      setIsRecordingReference(true);
    } catch (err) {
      console.error('Recording error', err);
    }
  };

  const stopRecordingReference = () => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
      setIsRecordingReference(false);
    }
  };

  const buildSystemInstruction = () => {
    const lockNote = isLocked ? "هذه الشخصية ثابتة ومستقرة، لا تغير أسلوبك أبداً." : "";
    const intensityNote = selectedMood.id !== 'neutral' ? `اجعل تأثير ${selectedMood.label} بنسبة شدة ${effectIntensity}% واضحة جداً.` : "";
    return `أنت مساعد صوتي ذكي تدعى "هزاع". 
            القاعدة الذهبية للهجة: ${selectedDialect.instruction}
            النمط الشخصي المطلوب: ${selectedPersona.instruction}
            ${selectedSpeed.desc}
            ${lockNote}
            ${intensityNote}
            حافظ على هويتك المختارة في كل جملة تنطقها.`;
  };

  const previewVoice = async (voiceName: string, label: string) => {
    if (isPreviewing) return;
    setIsPreviewing(voiceName);
    stopAllAudio();
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `بأسلوب ترحيبي جداً وبحالة ${selectedMood.label}: أهلاً بك، أنا صوت ${label}، سأقوم بنطق نصوصك بأفضل جودة واحترافية. كيف أساعدك اليوم؟`;
      const response = await ai.models.generateContent({
        model: TTS_MODEL,
        contents: [{ parts: [{ text: prompt }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voiceName as any } } },
        },
      });
      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) await playAudioChunk(base64Audio);
    } catch (err) {
      console.error(err);
    } finally {
      setIsPreviewing(null);
    }
  };

  const handleStartLive = async () => {
    if (status !== ConnectionStatus.DISCONNECTED) return;
    setStatus(ConnectionStatus.CONNECTING);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;

      const sessionPromise = ai.live.connect({
        model: LIVE_MODEL,
        callbacks: {
          onopen: () => setStatus(ConnectionStatus.CONNECTED),
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) currentOutputTransRef.current += message.serverContent.outputTranscription.text;
            else if (message.serverContent?.inputTranscription) currentInputTransRef.current += message.serverContent.inputTranscription.text;

            if (message.serverContent?.turnComplete) {
              const uText = currentInputTransRef.current.trim();
              const aText = currentOutputTransRef.current.trim();
              if (uText) setTranscriptions(prev => [...prev, { id: Date.now().toString(), role: 'user', text: uText, timestamp: Date.now() }]);
              if (aText) setTranscriptions(prev => [...prev, { id: (Date.now() + 1).toString(), role: 'assistant', text: aText, timestamp: Date.now() }]);
              currentInputTransRef.current = '';
              currentOutputTransRef.current = '';
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) playAudioChunk(base64Audio);
            if (message.serverContent?.interrupted) stopAllAudio();
          },
          onerror: (err) => { setStatus(ConnectionStatus.ERROR); console.error(err); },
          onclose: () => handleStopLive()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: selectedVoice } } },
          systemInstruction: buildSystemInstruction(),
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });

      sessionRef.current = await sessionPromise;
      const source = inputAudioContextRef.current!.createMediaStreamSource(stream);
      const scriptProcessor = inputAudioContextRef.current!.createScriptProcessor(4096, 1, 1);
      scriptProcessor.onaudioprocess = (event) => {
        const inputData = event.inputBuffer.getChannelData(0);
        const int16 = new Int16Array(inputData.length);
        for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
        sessionRef.current?.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } });
      };
      source.connect(scriptProcessor);
      scriptProcessor.connect(inputAudioContextRef.current!.destination);
    } catch (err) { setStatus(ConnectionStatus.ERROR); }
  };

  const playAudioChunk = async (base64: string) => {
    if (!outputAudioContextRef.current) outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const ctx = outputAudioContextRef.current;
    setIsAiSpeaking(true);
    nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
    const audioBuffer = await decodeAudioData(decode(base64), ctx, 24000, 1);

    if (mode === 'tts') {
      setLastAudioBuffer(audioBuffer);
    }

    const source = ctx.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(ctx.destination);
    source.onended = () => {
      activeSourcesRef.current.delete(source);
      if (activeSourcesRef.current.size === 0) setIsAiSpeaking(false);
    };
    source.start(nextStartTimeRef.current);
    nextStartTimeRef.current += audioBuffer.duration;
    activeSourcesRef.current.add(source);
  };

  const handleStopLive = () => {
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}
    stopAllAudio();
    if (mediaStreamRef.current) mediaStreamRef.current.getTracks().forEach(track => track.stop());
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    sessionRef.current = null;
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const generateTTS = async () => {
    if (!ttsText.trim() || isGeneratingTts) return;
    setIsGeneratingTts(true);
    setLastAudioBuffer(null);
    stopAllAudio();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      if (referenceAudio) {
        const instruction = `أنت هزاع المساعد الذكي. انطق النص التالي محاكياً بدقة نبرة وأسلوب التسجيل الصوتي المرفق. حافظ على اللهجة: ${selectedDialect.label}. الشدة المطلوبة للتأثير هي ${effectIntensity}%. النص: "${ttsText}"`;
        const response = await ai.models.generateContent({
          model: LIVE_MODEL,
          contents: [
            { parts: [
              { inlineData: { data: referenceAudio, mimeType: 'audio/webm' } },
              { text: instruction }
            ]}
          ],
          config: {
            responseModalities: [Modality.AUDIO],
          }
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData)?.inlineData?.data;
        if (base64Audio) await playAudioChunk(base64Audio);
      } else {
        const fullPrompt = `أنت هزاع. النمط: ${selectedPersona.instruction}. اللهجة: ${selectedDialect.instruction}. المود: ${selectedMood.prompt}. الشدة: ${effectIntensity}%. السرعة: ${selectedSpeed.desc}. النص: "${ttsText}"`;
        const response = await ai.models.generateContent({
          model: TTS_MODEL,
          contents: [{ parts: [{ text: fullPrompt }] }],
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: selectedVoice } } },
          },
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (base64Audio) await playAudioChunk(base64Audio);
      }
    } catch (err) { 
      console.error(err); 
    } finally { 
      setIsGeneratingTts(false); 
    }
  };

  const handleVoiceSelection = (v: typeof VOICE_OPTIONS[0]) => {
    if (isLocked) return;
    setSelectedVoice(v.id as VoiceType);
    previewVoice(v.id, v.label);
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 p-4 md:p-8 font-tajawal">
      <div className="max-w-7xl mx-auto flex flex-col gap-8">

        {/* Top Navigation & Brand */}
        <header className="flex flex-col md:flex-row items-center justify-between gap-6 bg-slate-800/40 p-6 rounded-[32px] border border-slate-700 shadow-xl backdrop-blur-md">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 bg-gradient-to-br from-teal-400 to-blue-500 rounded-2xl flex items-center justify-center shadow-lg shadow-teal-500/20">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
            </div>
            <div>
              <h1 className="text-3xl font-bold font-cairo text-white">هزاع ستوديو <span className="text-teal-400 text-sm font-normal">v5.5</span></h1>
              <p className="text-slate-400 text-sm">أقوى معمل أصوات بذكاء اصطناعي فائق</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={shareApp}
              className="flex items-center gap-2 bg-slate-900/50 hover:bg-slate-700 border border-slate-700 px-4 py-2.5 rounded-2xl text-sm font-bold transition-all text-slate-200 group"
            >
              <svg className="w-5 h-5 text-teal-400 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
              دعوة صديق
            </button>
            <div className="bg-slate-900/50 p-1.5 rounded-2xl border border-slate-700 flex gap-2">
              <button onClick={() => { setMode('live'); handleStopLive(); }} className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'live' ? 'bg-teal-500 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}>لايف</button>
              <button onClick={() => { setMode('tts'); handleStopLive(); }} className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'tts' ? 'bg-teal-500 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}>نص لصوت</button>
            </div>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Main Workspace (Left) */}
          <div className="lg:col-span-8 space-y-6">
            <div className="bg-slate-800/50 rounded-[48px] p-8 md:p-12 border border-slate-700 shadow-2xl min-h-[550px] flex flex-col relative overflow-hidden backdrop-blur-md">

              {mode === 'live' ? (
                <div className="flex-1 flex flex-col justify-center">
                  <Visualizer isActive={status === ConnectionStatus.CONNECTED} isSpeaking={isAiSpeaking} />
                  <div className="text-center mt-12">
                    <button
                      onClick={status === ConnectionStatus.CONNECTED ? handleStopLive : handleStartLive}
                      disabled={status === ConnectionStatus.CONNECTING}
                      className={`group relative w-36 h-36 rounded-full mx-auto flex items-center justify-center transition-all duration-500 ${status === ConnectionStatus.CONNECTED ? 'bg-red-500 shadow-[0_0_60px_rgba(239,68,68,0.4)]' : 'bg-teal-500 shadow-[0_0_60px_rgba(20,184,166,0.3)]'} hover:scale-110 active:scale-95`}
                    >
                      <div className={`absolute inset-0 rounded-full animate-ping opacity-20 group-hover:opacity-40 ${status === ConnectionStatus.CONNECTED ? 'bg-red-400' : 'bg-teal-400'}`}></div>
                      {status === ConnectionStatus.CONNECTED ? (
                        <svg className="w-16 h-16 text-white" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1-1H7a1 1 0 00-1 1v6a1 1 0 001 1h1a1 1 0 001-1V7zM14 7a1 1 0 00-1-1h-1a1 1 0 00-1 1v6a1 1 0 001 1h1a1 1 0 001-1V7z"/></svg>
                      ) : (
                        <svg className="w-16 h-16 text-white" fill="currentColor" viewBox="0 0 20 20"><path d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 006 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z"/></svg>
                      )}
                    </button>
                    <h3 className="text-2xl font-bold mt-10 text-white">
                      {status === ConnectionStatus.CONNECTED ? `هزاع يستمع إليك بلهجة ${selectedDialect.label}` : 'تحدث مع هزاع الآن'}
                    </h3>
                  </div>
                </div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="flex items-center justify-between mb-8">
                    <div className="flex items-center gap-3">
