      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) await playAudioChunk(base64Audio);
    } catch (err) { console.error(err); } finally { setIsPreviewing(null); }
  };

  const handleStartLive = async () => {
    if (status !== ConnectionStatus.DISCONNECTED) return;
    setStatus(ConnectionStatus.CONNECTING);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;

      // Fix: Follow the guidelines to solely rely on sessionPromise results to send data and avoid stale closures.
      const sessionPromise = ai.live.connect({
        model: LIVE_MODEL,
        callbacks: {
          onopen: () => setStatus(ConnectionStatus.CONNECTED),
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) currentOutputTransRef.current += message.serverContent.outputTranscription.text;
            else if (message.serverContent?.inputTranscription) currentInputTransRef.current += message.serverContent.inputTranscription.text;
            if (message.serverContent?.turnComplete) {
              const uText = currentInputTransRef.current.trim();
              const aText = currentOutputTransRef.current.trim();
              if (uText) setTranscriptions(prev => [...prev, { id: Date.now().toString(), role: 'user', text: uText, timestamp: Date.now() }]);
              if (aText) setTranscriptions(prev => [...prev, { id: (Date.now() + 1).toString(), role: 'assistant', text: aText, timestamp: Date.now() }]);
              currentInputTransRef.current = '';
              currentOutputTransRef.current = '';
            }
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) playAudioChunk(base64Audio);
            if (message.serverContent?.interrupted) stopAllAudio();
          },
          onerror: (err) => { setStatus(ConnectionStatus.ERROR); },
          onclose: () => handleStopLive()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: selectedVoice } } },
          systemInstruction: buildSystemInstruction(),
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        }
      });

      const source = inputAudioContextRef.current!.createMediaStreamSource(stream);
      const scriptProcessor = inputAudioContextRef.current!.createScriptProcessor(4096, 1, 1);
      scriptProcessor.onaudioprocess = (event) => {
        const inputData = event.inputBuffer.getChannelData(0);
        const int16 = new Int16Array(inputData.length);
        for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
        // Fix: Use sessionPromise.then inside onaudioprocess to prevent stale variable references.
        sessionPromise.then((session) => {
          session.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } });
        });
      };
      source.connect(scriptProcessor);
      scriptProcessor.connect(inputAudioContextRef.current!.destination);

      sessionRef.current = await sessionPromise;
    } catch (err) { setStatus(ConnectionStatus.ERROR); }
  };

  const playAudioChunk = async (base64: string) => {
    if (!outputAudioContextRef.current) outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const ctx = outputAudioContextRef.current;
    setIsAiSpeaking(true);
    nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
    const audioBuffer = await decodeAudioData(decode(base64), ctx, 24000, 1);
    if (mode === 'tts') setLastAudioBuffer(audioBuffer);
    const source = ctx.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(ctx.destination);
    source.onended = () => {
      activeSourcesRef.current.delete(source);
      if (activeSourcesRef.current.size === 0) setIsAiSpeaking(false);
    };
    source.start(nextStartTimeRef.current);
    nextStartTimeRef.current += audioBuffer.duration;
    activeSourcesRef.current.add(source);
  };

  const handleStopLive = () => {
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}
    stopAllAudio();
    if (mediaStreamRef.current) mediaStreamRef.current.getTracks().forEach(track => track.stop());
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    sessionRef.current = null;
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const generateTTS = async () => {
    if (!ttsText.trim() || isGeneratingTts) return;
    setIsGeneratingTts(true);
    setLastAudioBuffer(null);
    stopAllAudio();
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      if (referenceAudio) {
        const instruction = `أنت هزاع المساعد الذكي. انطق النص التالي مستنسخاً تماماً نبرة وأسلوب التسجيل المرفق. الشدة: ${effectIntensity}%. النص: "${ttsText}"`;
        const response = await ai.models.generateContent({
          model: LIVE_MODEL,
          contents: [{ parts: [{ inlineData: { data: referenceAudio, mimeType: 'audio/webm' } }, { text: instruction }]}],
          config: { responseModalities: [Modality.AUDIO] }
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData)?.inlineData?.data;
        if (base64Audio) await playAudioChunk(base64Audio);
      } else {
        const fullPrompt = `أنت هزاع. النمط: ${selectedPersona.instruction}. اللهجة: ${selectedDialect.instruction}. المود: ${selectedMood.prompt}. الشدة: ${effectIntensity}%. السرعة: ${selectedSpeed.desc}. النص: "${ttsText}"`;
        const response = await ai.models.generateContent({
          model: TTS_MODEL,
          contents: [{ parts: [{ text: fullPrompt }] }],
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: selectedVoice } } },
          },
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (base64Audio) await playAudioChunk(base64Audio);
      }
    } catch (err) { console.error(err); } finally { setIsGeneratingTts(false); }
  };

