        <header className="flex flex-col md:flex-row items-center justify-between gap-6 bg-slate-800/40 p-6 rounded-[32px] border border-slate-700 shadow-xl backdrop-blur-md">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 bg-gradient-to-br from-teal-400 to-blue-500 rounded-2xl flex items-center justify-center shadow-lg shadow-teal-500/20">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
            </div>
            <div>
              <h1 className="text-3xl font-bold font-cairo text-white">هزاع ستوديو <span className="text-teal-400 text-sm font-normal">PRO HD</span></h1>
              <p className="text-slate-400 text-sm">أقوى منصة توليد ومحاكاة أصوات احترافية</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button onClick={shareApp} className="flex items-center gap-2 bg-slate-900/50 hover:bg-slate-700 border border-slate-700 px-4 py-2.5 rounded-2xl text-sm font-bold transition-all"><svg className="w-5 h-5 text-teal-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>مشاركة</button>
            <div className="bg-slate-900/50 p-1.5 rounded-2xl border border-slate-700 flex gap-2">
              <button onClick={() => { setMode('live'); handleStopLive(); }} className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'live' ? 'bg-teal-500 text-white' : 'text-slate-400'}`}>لايف</button>
              <button onClick={() => { setMode('tts'); handleStopLive(); }} className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'tts' ? 'bg-teal-500 text-white' : 'text-slate-400'}`}>الاستوديو</button>
