                    <div className="flex gap-4 items-center">
                       {isAiSpeaking && <div className="flex gap-1 items-center"><div className="w-1.5 bg-teal-500 animate-bounce h-6 rounded-full shadow-[0_0_10px_#2dd4bf]"></div><div className="w-1.5 bg-blue-500 animate-bounce h-9 delay-75 rounded-full shadow-[0_0_10px_#3b82f6]"></div><div className="w-1.5 bg-teal-500 animate-bounce h-5 delay-150 rounded-full shadow-[0_0_10px_#2dd4bf]"></div></div>}
                       <span className="text-sm font-medium text-slate-400">{isGeneratingTts ? 'يتم التوليد بجودة HD...' : (isAiSpeaking ? 'هزاع يتحدث الآن' : 'جاهز للتوليد')}</span>
