                <section>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-5">تقمص الشخصية</label>
                  <div className="grid grid-cols-2 gap-2.5 max-h-48 overflow-y-auto custom-scrollbar p-1">
                    {PERSONA_OPTIONS.map(p => (
