                    {PERSONA_OPTIONS.map(p => (
                      <button key={p.id} onClick={() => { if (!isLocked) { setSelectedPersona(p); previewVoice(selectedVoice, VOICE_OPTIONS.find(v => v.id === selectedVoice)!.label); } }} className={`p-3 rounded-2xl border text-xs font-bold transition-all ${selectedPersona.id === p.id ? 'bg-blue-500/10 border-blue-500/50 text-blue-100' : 'bg-slate-900/40 border-slate-800 text-slate-500'}`}>{p.icon} {p.label}</button>
                    ))}
                  </div>
