                <section>
                  <label className="text-xs font-bold text-slate-500 block mb-4">المزاج والقوة</label>
                  <div className="grid grid-cols-2 gap-2 mb-4">
                    {MOOD_OPTIONS.map(m => (
                      <button key={m.id} onClick={() => { if (!isLocked) { setSelectedMood(m); previewVoice(selectedVoice, VOICE_OPTIONS.find(v => v.id === selectedVoice)!.label); } }} className={`p-2.5 rounded-xl border text-[10px] font-bold transition-all ${selectedMood.id === m.id ? 'bg-orange-500/10 border-orange-500/50 text-orange-100' : 'bg-slate-900/40 border-slate-800 text-slate-500'}`}>{m.label}</button>
                    ))}
                  </div>
                  {selectedMood.id !== 'neutral' && (
                    <div className="p-4 bg-slate-900/40 rounded-2xl border border-slate-800">
                       <input type="range" min="0" max="100" value={effectIntensity} onChange={(e) => setEffectIntensity(parseInt(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-teal-500" />
                    </div>
                  )}
                </section>

                <section>
                  <label className="text-xs font-bold text-slate-500 block mb-4">اختيار الصوت</label>
                  <div className="space-y-3">
                    {VOICE_OPTIONS.map(v => (
                      <button key={v.id} onClick={() => handleVoiceChange(v)} className={`w-full flex items-center justify-between p-4 rounded-[20px] border transition-all ${selectedVoice === v.id ? 'bg-purple-500/10 border-purple-500/50 text-purple-100' : 'bg-slate-900/40 border-slate-800 text-slate-500 hover:border-slate-700'}`}>
                        <div className="flex items-center gap-4 text-right">
                          <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-xs font-black ${selectedVoice === v.id ? 'bg-purple-500 text-white' : 'bg-slate-800'}`}>{v.label[0]}</div>
                          <div><div className="text-sm font-bold">{v.label}</div><div className="text-[10px] opacity-50">{v.desc}</div></div>
                        </div>
                        {isPreviewing === v.id && <div className="w-4 h-4 border-2 border-purple-400 border-t-transparent rounded-full animate-spin"></div>}
                      </button>
                    ))}
                  </div>
                </section>
              </div>
            </div>
          </aside>
        </div>
      </div>
    </div>
  );
};

export default App;

