    setIsAiSpeaking(false);
  };

  const playSFX = async (effect: SoundEffect) => {
    if (!outputAudioContextRef.current) outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    const ctx = outputAudioContextRef.current;

    setPlayingSfxId(effect.id);
    try {
      const response = await fetch(effect.url);
      const arrayBuffer = await response.arrayBuffer();
      const audioBuffer = await ctx.decodeAudioData(arrayBuffer);

      const source = ctx.createBufferSource();
      const gainNode = ctx.createGain();

      source.buffer = audioBuffer;
      source.playbackRate.value = sfxPitch;
      gainNode.gain.value = sfxVolume;

      source.connect(gainNode);
      gainNode.connect(ctx.destination);

      source.onended = () => setPlayingSfxId(null);
      source.start();
    } catch (err) {
      console.error('Error playing SFX:', err);
      setPlayingSfxId(null);
    }
  };

  const downloadAudio = () => {
    if (!lastAudioBuffer) return;
    const blob = audioBufferToWav(lastAudioBuffer);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Hazza_Voice_${Date.now()}.mp3`; 
    a.click();
    URL.revokeObjectURL(url);
  };

  const startRecordingReference = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;
      audioChunksRef.current = [];
      recorder.ondataavailable = (e) => audioChunksRef.current.push(e.data);
      recorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = () => {
          const base64data = reader.result as string;
          setReferenceAudio(base64data.split(',')[1]);
        };
        stream.getTracks().forEach(t => t.stop());
      };
      recorder.start();
      setIsRecordingReference(true);
    } catch (err) { console.error(err); }
  };

  const stopRecordingReference = () => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
      setIsRecordingReference(false);
    }
  };

  const buildSystemInstruction = () => {
    const intensityNote = selectedMood.id !== 'neutral' ? `اجعل تأثير ${selectedMood.label} بنسبة شدة ${effectIntensity}% حقيقية للغاية.` : "";
    return `أنت هزاع المساعد الذكي. 
            اللهجة: ${selectedDialect.instruction}
            النمط: ${selectedPersona.instruction}
            ${intensityNote}
            السرعة المطلوبة: ${speechRate}x.
            التنغيم (Pitch): ${speechIntonation}x.
            حافظ على هويتك طوال الوقت.`;
  };

  const previewVoice = async (voiceId: string, label: string) => {
    if (isPreviewing) return;
    setIsPreviewing(voiceId);
    stopAllAudio();
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const moodText = selectedMood.id !== 'neutral' ? `بأسلوب ${selectedMood.label}` : "بأسلوبك المعتاد";
      const prompt = `${moodText}: أهلاً بك، أنا صوت ${label} من استوديو هزاع، سأقوم بنطق نصوصك بدقة وجودة فائقة. أنا مستعد للعمل معك الآن!`;

      const response = await ai.models.generateContent({
        model: TTS_MODEL,
        contents: [{ parts: [{ text: prompt }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { 
            voiceConfig: { prebuiltVoiceConfig: { voiceName: voiceId as any } } 
          },
        },
      });
      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) await playAudioChunk(base64Audio);
    } catch (err) { console.error(err); } finally { setIsPreviewing(null); }
  };

  const handleStartLive = async () => {
    if (status !== ConnectionStatus.DISCONNECTED) return;
    setStatus(ConnectionStatus.CONNECTING);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;

      const sessionPromise = ai.live.connect({
        model: LIVE_MODEL,
        callbacks: {
          onopen: () => setStatus(ConnectionStatus.CONNECTED),
          onmessage: async (message: LiveServerMessage) => {
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) playAudioChunk(base64Audio);
            if (message.serverContent?.interrupted) stopAllAudio();
          },
          onerror: () => setStatus(ConnectionStatus.ERROR),
          onclose: () => handleStopLive()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: selectedVoice } } },
          systemInstruction: buildSystemInstruction(),
        }
      });

      const source = inputAudioContextRef.current!.createMediaStreamSource(stream);
      const scriptProcessor = inputAudioContextRef.current!.createScriptProcessor(4096, 1, 1);
      scriptProcessor.onaudioprocess = (event) => {
        const inputData = event.inputBuffer.getChannelData(0);
        const int16 = new Int16Array(inputData.length);
        for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
        sessionPromise.then((session) => {
          session.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } });
        });
      };
      source.connect(scriptProcessor);
      scriptProcessor.connect(inputAudioContextRef.current!.destination);
      sessionRef.current = await sessionPromise;
    } catch (err) { setStatus(ConnectionStatus.ERROR); }
  };

  const playAudioChunk = async (base64: string) => {
    if (!outputAudioContextRef.current) outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const ctx = outputAudioContextRef.current;
    setIsAiSpeaking(true);
    nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
    const audioBuffer = await decodeAudioData(decode(base64), ctx, 24000, 1);
    if (mode === 'tts') setLastAudioBuffer(audioBuffer);
    const source = ctx.createBufferSource();
    source.buffer = audioBuffer;

    // Apply pitch shifts using playbackRate
    source.playbackRate.value = speechIntonation;

    source.connect(ctx.destination);
    source.onended = () => {
      activeSourcesRef.current.delete(source);
      if (activeSourcesRef.current.size === 0) setIsAiSpeaking(false);
    };
    source.start(nextStartTimeRef.current);
    nextStartTimeRef.current += audioBuffer.duration / speechIntonation;
    activeSourcesRef.current.add(source);
  };

  const handleStopLive = () => {
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}
    stopAllAudio();
    if (mediaStreamRef.current) mediaStreamRef.current.getTracks().forEach(track => track.stop());
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    sessionRef.current = null;
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const generateTTS = async () => {
    if (!ttsText.trim() || isGeneratingTts) return;
    setIsGeneratingTts(true);
    setLastAudioBuffer(null);
    stopAllAudio();
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const promptPrefix = `أنت هزاع المساعد الذكي. انطق النص التالي بسرعة ${speechRate}x وتنغيم ${speechIntonation}x. `;

      if (referenceAudio) {
        const instruction = `${promptPrefix}انطق النص التالي مستنسخاً تماماً نبرة وأسلوب التسجيل المرفق. الشدة: ${effectIntensity}%. النص: "${ttsText}"`;
        const response = await ai.models.generateContent({
          model: LIVE_MODEL,
          contents: [{ parts: [{ inlineData: { data: referenceAudio, mimeType: 'audio/webm' } }, { text: instruction }]}],
          config: { responseModalities: [Modality.AUDIO] }
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData)?.inlineData?.data;
        if (base64Audio) await playAudioChunk(base64Audio);
      } else {
        const fullPrompt = `${promptPrefix} النمط: ${selectedPersona.instruction}. اللهجة: ${selectedDialect.instruction}. المود: ${selectedMood.prompt}. الشدة: ${effectIntensity}%. النص: "${ttsText}"`;
        const response = await ai.models.generateContent({
          model: TTS_MODEL,
          contents: [{ parts: [{ text: fullPrompt }] }],
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: selectedVoice } } },
          },
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (base64Audio) await playAudioChunk(base64Audio);
      }
    } catch (err) { console.error(err); } finally { setIsGeneratingTts(false); }
  };

  const confirmPendingVoice = () => {
    setSelectedVoice(pendingVoice);
    const voiceObj = VOICE_OPTIONS.find(v => v.id === pendingVoice);
    if (voiceObj) previewVoice(voiceObj.id, voiceObj.label);
  };

  const filteredVoices = VOICE_OPTIONS.filter(v => {
    if (genderFilter === 'all') return true;
    return v.gender === genderFilter;
  });

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 p-4 md:p-8 font-tajawal">
      <div className="max-w-7xl mx-auto flex flex-col gap-8">

        <header className="flex flex-col md:flex-row items-center justify-between gap-6 bg-slate-800/40 p-6 rounded-[32px] border border-slate-700 shadow-xl backdrop-blur-md">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 bg-gradient-to-br from-teal-400 to-blue-500 rounded-2xl flex items-center justify-center shadow-lg">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
            </div>
            <div>
              <h1 className="text-3xl font-bold font-cairo text-white">هزاع ستوديو <span className="text-teal-400 text-sm font-normal">V3.5</span></h1>
              <p className="text-slate-400 text-sm">أقوى منصة توليد أصوات عربية احترافية</p>
            </div>
          </div>
          <div className="flex bg-slate-900/50 p-1.5 rounded-2xl border border-slate-700">
            <button onClick={() => { setMode('live'); handleStopLive(); }} className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'live' ? 'bg-teal-500 text-white' : 'text-slate-400'}`}>محادثة لايف</button>
            <button onClick={() => { setMode('tts'); handleStopLive(); }} className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'tts' ? 'bg-teal-500 text-white' : 'text-slate-400'}`}>استوديو النصوص</button>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-8 space-y-6">
            <div className="bg-slate-800/50 rounded-[48px] p-8 md:p-12 border border-slate-700 shadow-2xl min-h-[550px] flex flex-col relative backdrop-blur-md">
              {mode === 'live' ? (
                <div className="flex-1 flex flex-col justify-center">
                  <Visualizer isActive={status === ConnectionStatus.CONNECTED} isSpeaking={isAiSpeaking} />
                  <div className="text-center mt-12">
                    <button onClick={status === ConnectionStatus.CONNECTED ? handleStopLive : handleStartLive} disabled={status === ConnectionStatus.CONNECTING} className={`relative w-36 h-36 rounded-full mx-auto flex items-center justify-center transition-all ${status === ConnectionStatus.CONNECTED ? 'bg-red-500 shadow-[0_0_60px_rgba(239,68,68,0.4)]' : 'bg-teal-500 shadow-[0_0_60px_rgba(20,184,166,0.3)]'}`}>
                      <div className={`absolute inset-0 rounded-full animate-ping opacity-20 ${status === ConnectionStatus.CONNECTED ? 'bg-red-400' : 'bg-teal-400'}`}></div>
                      <svg className="w-16 h-16 text-white" fill="currentColor" viewBox="0 0 20 20">{status === ConnectionStatus.CONNECTED ? <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1-1H7a1 1 0 00-1 1v6a1 1 0 001 1h1a1 1 0 001-1V7zM14 7a1 1 0 00-1-1h-1a1 1 0 00-1 1v6a1 1 0 001 1h1a1 1 0 001-1V7z"/> : <path d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 006 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z"/>}</svg>
                    </button>
                    <h3 className="text-2xl font-bold mt-10 text-white">{status === ConnectionStatus.CONNECTED ? `هزاع يستمع...` : 'ابدأ حواراً فورياً الآن'}</h3>
                  </div>
                </div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="flex items-center justify-between mb-8">
                    <h2 className="text-2xl font-bold">معالج النصوص</h2>
                    <div className="flex items-center gap-2">
                       <button onClick={isRecordingReference ? stopRecordingReference : startRecordingReference} className={`flex items-center gap-2 px-4 py-2 rounded-xl border transition-all ${isRecordingReference ? 'bg-red-500 text-white animate-pulse shadow-[0_0_20px_rgba(239,68,68,0.5)]' : 'bg-slate-900/50 text-slate-400 border-slate-700 hover:text-white'}`}>
                          <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 006 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z"/></svg>
                          <span className="text-xs font-bold">{isRecordingReference ? 'جارِ التسجيل...' : (referenceAudio ? 'نبرة مستنسخة جاهزة' : 'استنساخ نبرة صوت')}</span>
                       </button>
                    </div>
                  </div>
                  <textarea value={ttsText} onChange={(e) => setTtsText(e.target.value)} readOnly={isGeneratingTts} placeholder="اكتب النص الذي تريده بصوت هزاع هنا..." className="flex-1 bg-slate-900/60 border border-slate-700/50 rounded-[32px] p-8 text-2xl leading-relaxed text-slate-100 outline-none focus:ring-4 focus:ring-teal-500/10 transition-all resize-none shadow-inner scrollbar-hide" />

                  {/* Fine-tuning TTS controls */}
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-6">
                    <div className="p-4 bg-slate-900/40 rounded-3xl border border-slate-700/40">
                      <div className="flex justify-between mb-2">
                        <span className="text-xs font-bold text-slate-500">سرعة الكلام</span>
                        <span className="text-xs font-bold text-teal-400">{speechRate.toFixed(1)}x</span>
                      </div>
                      <div className="flex gap-2 mb-3">
                        {SPEED_PRESETS.map(p => (
                          <button key={p.id} onClick={() => setSpeechRate(p.value)} className={`flex-1 py-1 rounded-lg text-[10px] font-bold transition-all ${speechRate === p.value ? 'bg-teal-500 text-white' : 'bg-slate-800 text-slate-400'}`}>{p.label}</button>
                        ))}
                      </div>
                      <input type="range" min="0.5" max="2.0" step="0.1" value={speechRate} onChange={(e) => setSpeechRate(parseFloat(e.target.value))} className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-teal-400" />
                    </div>
                    <div className="p-4 bg-slate-900/40 rounded-3xl border border-slate-700/40">
                      <div className="flex justify-between mb-2">
                        <span className="text-xs font-bold text-slate-500">التنغيم (Pitch)</span>
                        <span className="text-xs font-bold text-blue-400">{speechIntonation.toFixed(1)}x</span>
                      </div>
                      <input type="range" min="0.5" max="2.0" step="0.1" value={speechIntonation} onChange={(e) => setSpeechIntonation(parseFloat(e.target.value))} className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-400" />
                    </div>
                  </div>

                  <div className="mt-8 flex flex-col md:flex-row items-center justify-between gap-4 bg-slate-900/30 p-4 rounded-3xl border border-slate-700/30">
                    <div className="flex gap-4 items-center">
                       {isAiSpeaking && <div className="flex gap-1 items-center"><div className="w-1.5 bg-teal-500 animate-bounce h-6 rounded-full"></div><div className="w-1.5 bg-blue-500 animate-bounce h-9 delay-75 rounded-full"></div><div className="w-1.5 bg-teal-500 animate-bounce h-5 delay-150 rounded-full"></div></div>}
                       <span className="text-sm font-medium text-slate-400">{isGeneratingTts ? 'يتم التوليد الآن...' : 'بانتظار النص'}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      {lastAudioBuffer && !isGeneratingTts && (
                        <button onClick={downloadAudio} className="bg-slate-800 hover:bg-slate-700 text-slate-200 px-6 py-4 rounded-[20px] font-bold text-lg border border-slate-700 flex items-center gap-3 transition-all transform hover:-translate-y-1">
                          <svg className="w-6 h-6 text-teal-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                          تحميل المقطع
                        </button>
                      )}
                      <button onClick={generateTTS} disabled={!ttsText.trim() || isGeneratingTts} className="bg-gradient-to-r from-teal-500 to-blue-600 hover:from-teal-600 hover:to-blue-700 disabled:opacity-50 text-white px-12 py-4 rounded-[20px] font-bold text-xl shadow-2xl transform hover:-translate-y-1 active:scale-95">
                        {isGeneratingTts ? <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : 'توليد الصوت'}
                      </button>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>

          <aside className="lg:col-span-4 space-y-6">
            <div className="bg-slate-800/80 rounded-[40px] border border-slate-700 p-8 shadow-2xl backdrop-blur-xl">
              <div className="flex items-center justify-between mb-8">
                <h3 className="text-xl font-bold text-white">إعدادات الصوت</h3>
                <button onClick={() => setIsLocked(!isLocked)} className={`p-2.5 rounded-xl border transition-all ${isLocked ? 'bg-orange-500 text-white border-orange-400' : 'bg-slate-900/50 border-slate-700 text-slate-500'}`}>
                   <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
                </button>
              </div>

              <div className={`space-y-8 ${isLocked ? 'opacity-40 pointer-events-none blur-[1px]' : ''}`}>

                {/* Voice Selection with Gender Filter */}
                <section>
                  <label className="text-xs font-bold text-slate-500 block mb-4">اختيار الصوت (ذكر أو أنثى)</label>

                  {/* Gender Toggle */}
                  <div className="flex gap-2 mb-4 bg-slate-900/60 p-1.5 rounded-2xl border border-slate-800">
                    <button onClick={() => setGenderFilter('all')} className={`flex-1 py-2 rounded-xl text-xs font-bold transition-all ${genderFilter === 'all' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}>الكل</button>
                    <button onClick={() => setGenderFilter('female')} className={`flex-1 py-2 rounded-xl text-xs font-bold transition-all ${genderFilter === 'female' ? 'bg-pink-600/20 text-pink-400 border border-pink-500/30' : 'text-slate-500 hover:text-slate-300'}`}>أنثى</button>
                    <button onClick={() => setGenderFilter('male')} className={`flex-1 py-2 rounded-xl text-xs font-bold transition-all ${genderFilter === 'male' ? 'bg-blue-600/20 text-blue-400 border border-blue-500/30' : 'text-slate-500 hover:text-slate-300'}`}>ذكر</button>
                  </div>

                  <div className="space-y-3">
                    {filteredVoices.map(v => (
                      <div key={v.id} className="relative">
                        <button 
                          onClick={() => setPendingVoice(v.id as VoiceType)} 
                          className={`w-full flex items-center justify-between p-4 rounded-[20px] border transition-all ${pendingVoice === v.id ? 'bg-purple-500/10 border-purple-500/50 text-purple-100' : 'bg-slate-900/40 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                        >
                          <div className="flex items-center gap-4 text-right">
                            <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-xs font-black ${selectedVoice === v.id ? 'bg-teal-500 text-white' : 'bg-slate-800'}`}>{v.label[0]}</div>
                            <div>
                              <div className="text-sm font-bold flex items-center gap-2">
                                {v.label}
                                {v.gender === 'female' ? <span className="text-[10px] text-pink-400">♀</span> : <span className="text-[10px] text-blue-400">♂</span>}
                              </div>
                              <div className="text-[10px] opacity-50">{v.desc}</div>
                            </div>
                          </div>
                          <button onClick={(e) => { e.stopPropagation(); previewVoice(v.id, v.label); }} className="p-2 bg-slate-800/50 rounded-lg hover:text-teal-400 transition-colors">
                            <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z"/></svg>
                          </button>
                        </button>
                        {pendingVoice === v.id && selectedVoice !== v.id && (
                          <button 
                            onClick={confirmPendingVoice}
                            className="absolute -top-2 left-2 bg-teal-500 text-white text-[10px] font-bold px-3 py-1 rounded-full shadow-lg border border-teal-400 animate-bounce"
                          >
                            تأكيد الاختيار
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                </section>

                <section>
                  <label className="text-xs font-bold text-slate-500 block mb-4">اللهجة والنمط</label>
                  <div className="grid grid-cols-2 gap-2 mb-4">
                    {DIALECT_OPTIONS.slice(0, 4).map(d => (
                      <button key={d.id} onClick={() => setSelectedDialect(d)} className={`p-3 rounded-2xl border text-[11px] font-bold transition-all ${selectedDialect.id === d.id ? 'bg-teal-500/10 border-teal-500/50 text-teal-100' : 'bg-slate-900/40 border-slate-800 text-slate-500'}`}>{d.flag} {d.label}</button>
                    ))}
                  </div>
                  <div className="grid grid-cols-2 gap-2 max-h-40 overflow-y-auto custom-scrollbar p-1">
                    {PERSONA_OPTIONS.map(p => (
                      <button key={p.id} onClick={() => setSelectedPersona(p)} className={`p-3 rounded-2xl border text-[10px] font-bold transition-all ${selectedPersona.id === p.id ? 'bg-blue-500/10 border-blue-500/50 text-blue-100' : 'bg-slate-900/40 border-slate-800 text-slate-500'}`}>{p.icon} {p.label}</button>
                    ))}
                  </div>
                </section>

                <section>
                  <label className="text-xs font-bold text-slate-500 block mb-4">المزاج والقوة</label>
                  <div className="grid grid-cols-2 gap-2 mb-4">
                    {MOOD_OPTIONS.slice(0, 6).map(m => (
                      <button key={m.id} onClick={() => setSelectedMood(m)} className={`p-2.5 rounded-xl border text-[10px] font-bold transition-all ${selectedMood.id === m.id ? 'bg-orange-500/10 border-orange-500/50 text-orange-100' : 'bg-slate-900/40 border-slate-800 text-slate-500'}`}>{m.label}</button>
                    ))}
                  </div>
                  {selectedMood.id !== 'neutral' && (
                    <div className="p-4 bg-slate-900/40 rounded-2xl border border-slate-800">
                       <input type="range" min="0" max="100" value={effectIntensity} onChange={(e) => setEffectIntensity(parseInt(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-teal-500" />
                    </div>
                  )}
                </section>

                <section>
                  <label className="text-xs font-bold text-slate-500 block mb-4">المؤثرات الصوتية</label>
                  <div className="grid grid-cols-2 gap-2 mb-6">
                    {SOUND_EFFECTS.map(effect => (
                      <button 
                        key={effect.id} 
                        onClick={() => playSFX(effect)} 
                        className={`p-3 rounded-2xl border flex items-center gap-2 transition-all ${playingSfxId === effect.id ? 'bg-yellow-500/20 border-yellow-500 text-yellow-100' : 'bg-slate-900/40 border-slate-800 text-slate-500 hover:border-slate-600'}`}
                      >
                        <span className="text-lg">{effect.icon}</span>
                        <span className="text-[10px] font-bold">{effect.label}</span>
                      </button>
                    ))}
                  </div>
                  <div className="space-y-4 p-4 bg-slate-900/40 rounded-2xl border border-slate-800">
                    <div>
                      <div className="flex justify-between text-[10px] font-bold text-slate-500 mb-1">
                        <span>مستوى صوت المؤثر</span>
                        <span>{Math.round(sfxVolume * 100)}%</span>
                      </div>
                      <input type="range" min="0" max="1" step="0.01" value={sfxVolume} onChange={(e) => setSfxVolume(parseFloat(e.target.value))} className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-teal-400" />
                    </div>
                  </div>
                </section>
              </div>
            </div>
          </aside>
        </div>
      </div>
    </div>
  );
};

export default App;

