const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('tts');
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [isGeneratingTts, setIsGeneratingTts] = useState(false);
  const [isPreviewing, setIsPreviewing] = useState<string | null>(null);

  const [ttsText, setTtsText] = useState('');
  const [selectedVoiceId, setSelectedVoiceId] = useState<string>('f1');
  const [pendingVoiceId, setPendingVoiceId] = useState<string>('f1');
  const [genderFilter, setGenderFilter] = useState<Gender>('all');

  const [selectedDialect, setSelectedDialect] = useState(DIALECT_OPTIONS[0]);
  const [selectedMood, setSelectedMood] = useState(MOOD_OPTIONS[5]); 
  const [effectIntensity, setEffectIntensity] = useState(80); 
  const [speechPitch, setSpeechPitch] = useState(1.0); 

  // Player States
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [audioProgress, setAudioProgress] = useState(0);
  const [audioDuration, setAudioDuration] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const activeSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  useEffect(() => {
    if (audioRef.current) {
      const updateProgress = () => {
        setAudioProgress(audioRef.current?.currentTime || 0);
      };
      const onEnded = () => setIsPlaying(false);
      const onLoadedMetadata = () => setAudioDuration(audioRef.current?.duration || 0);

      const el = audioRef.current;
      el.addEventListener('timeupdate', updateProgress);
      el.addEventListener('ended', onEnded);
      el.addEventListener('loadedmetadata', onLoadedMetadata);
      return () => {
        el.removeEventListener('timeupdate', updateProgress);
        el.removeEventListener('ended', onEnded);
        el.removeEventListener('loadedmetadata', onLoadedMetadata);
      };
    }
  }, [audioUrl]);

  const stopAllAudio = () => {
    activeSourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
    activeSourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setIsAiSpeaking(false);
    if (audioRef.current) {
      audioRef.current.pause();
      setIsPlaying(false);
    }
  };

  const buildSystemInstruction = () => {
    const voice = VOICE_PERSONAS.find(v => v.id === selectedVoiceId) || VOICE_PERSONAS[0];
    const moodNote = selectedMood.id !== 'neutral' ? `التأثير: ${selectedMood.label} بنسبة ${effectIntensity}%` : "";
    return `أنت هزاع، مساعد ذكي. الشخصية: ${voice.instruction} اللهجة: ${selectedDialect.instruction} ${moodNote} نبرة: ${speechPitch.toFixed(1)}x.`;
  };

  const previewVoice = async (vId: string) => {
    if (isPreviewing) return;
    const voice = VOICE_PERSONAS.find(v => v.id === vId);
    if (!voice) return;
    setIsPreviewing(vId);
    stopAllAudio();
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const greeting = `أهلاً بك في تطبيق هزاع الاحترافي. أنا ${voice.name}، جاهز لمساعدتك بنبرتي الـ${voice.desc}. هل نعتمد هذا الصوت؟`;
      const response = await ai.models.generateContent({
        model: TTS_MODEL,
        contents: [{ parts: [{ text: greeting }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice.base as any } } },
        },
      });
      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        const ctx = new AudioContext();
        const buffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
        const wavBlob = audioBufferToWav(buffer);
        const url = URL.createObjectURL(wavBlob);
        setAudioUrl(url);
        setIsPlaying(true);
        setTimeout(() => audioRef.current?.play(), 100);
      }
    } catch (err) { console.error(err); } finally { setIsPreviewing(null); }
  };

  const handleStartLive = async () => {
    if (status !== ConnectionStatus.DISCONNECTED) return;
    setStatus(ConnectionStatus.CONNECTING);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      inputAudioContextRef.current = new AudioContext({ sampleRate: 16000 });
      outputAudioContextRef.current = new AudioContext({ sampleRate: 24000 });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const voice = VOICE_PERSONAS.find(v => v.id === selectedVoiceId) || VOICE_PERSONAS[0];
      const sessionPromise = ai.live.connect({
        model: LIVE_MODEL,
        callbacks: {
          onopen: () => setStatus(ConnectionStatus.CONNECTED),
          onmessage: async (message: LiveServerMessage) => {
            const base64 = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64) {
              setIsAiSpeaking(true);
              const ctx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(base64), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.playbackRate.value = speechPitch;
              source.connect(ctx.destination);
              source.onended = () => {
                activeSourcesRef.current.delete(source);
                if (activeSourcesRef.current.size === 0) setIsAiSpeaking(false);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration / speechPitch;
              activeSourcesRef.current.add(source);
            }
          },
          onerror: () => setStatus(ConnectionStatus.ERROR),
          onclose: () => handleStopLive()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice.base } } },
          systemInstruction: buildSystemInstruction(),
        }
      });
      const source = inputAudioContextRef.current.createMediaStreamSource(stream);
      const scriptProcessor = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);
      scriptProcessor.onaudioprocess = (e) => {
        const input = e.inputBuffer.getChannelData(0);
        const int16 = new Int16Array(input.length);
        for (let i = 0; i < input.length; i++) int16[i] = input[i] * 32768;
        sessionPromise.then(s => s.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } }));
      };
      source.connect(scriptProcessor);
      scriptProcessor.connect(inputAudioContextRef.current.destination);
      sessionRef.current = await sessionPromise;
    } catch (err) { setStatus(ConnectionStatus.ERROR); }
  };

  const handleStopLive = () => {
    if (sessionRef.current) sessionRef.current.close();
    stopAllAudio();
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const generateTTS = async () => {
    if (!ttsText.trim() || isGeneratingTts) return;
    setIsGeneratingTts(true);
    stopAllAudio();
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const voice = VOICE_PERSONAS.find(v => v.id === selectedVoiceId) || VOICE_PERSONAS[0];
      const prompt = `تقمص شخصية: ${voice.instruction}. اللهجة: ${selectedDialect.instruction}. المزاج: ${selectedMood.prompt}. النبرة: ${speechPitch}x. النص: "${ttsText}"`;
      const response = await ai.models.generateContent({
        model: TTS_MODEL,
        contents: [{ parts: [{ text: prompt }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice.base as any } } },
        },
      });
      const base64 = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64) {
        const ctx = new AudioContext();
        const buffer = await decodeAudioData(decode(base64), ctx, 24000, 1);
        const wavBlob = audioBufferToWav(buffer);
        const url = URL.createObjectURL(wavBlob);
        setAudioUrl(url);
        setIsPlaying(true);
        setTimeout(() => audioRef.current?.play(), 100);
      }
    } catch (err) { console.error(err); } finally { setIsGeneratingTts(false); }
  };

  const togglePlayback = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const seek = (time: number) => {
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const skip = (seconds: number) => {
    if (audioRef.current) audioRef.current.currentTime += seconds;
  };

  const filteredVoices = VOICE_PERSONAS.filter(v => {
    if (genderFilter === 'all') return true;
    if (genderFilter === 'child') return v.category === 'child';
    return v.gender === genderFilter && v.category === 'adult';
  });

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 p-4 md:p-8 font-tajawal">
      <div className="max-w-7xl mx-auto flex flex-col gap-8">

        <header className="flex flex-col md:flex-row items-center justify-between gap-6 bg-slate-800/40 p-6 rounded-[32px] border border-slate-700 shadow-xl backdrop-blur-md">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 bg-gradient-to-br from-teal-400 to-blue-500 rounded-2xl flex items-center justify-center shadow-lg">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
            </div>
            <div>
              <h1 className="text-3xl font-bold font-cairo text-white">هزاع ستوديو <span className="text-teal-400 text-sm font-normal">PRO</span></h1>
              <p className="text-slate-400 text-sm">أقوى منصة توليد أصوات عربية احترافية</p>
            </div>
          </div>
          <div className="flex bg-slate-900/50 p-1.5 rounded-2xl border border-slate-700">
            <button onClick={() => { setMode('live'); handleStopLive(); }} className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'live' ? 'bg-teal-500 text-white shadow-lg' : 'text-slate-400'}`}>لايف</button>
            <button onClick={() => { setMode('tts'); handleStopLive(); }} className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'tts' ? 'bg-teal-500 text-white shadow-lg' : 'text-slate-400'}`}>الاستوديو</button>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-8 space-y-6">
            <div className="bg-slate-800/50 rounded-[48px] p-8 md:p-12 border border-slate-700 shadow-2xl min-h-[550px] flex flex-col relative backdrop-blur-md">
              {mode === 'live' ? (
