                        <a href={audioUrl} download="Hazza_Voice.wav" className="p-2 text-teal-400 hover:text-teal-300"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg></a>
                      </div>
                      <audio ref={audioRef} src={audioUrl} className="hidden" />
                    </div>
                  )}

                  <div className="flex items-center justify-center">
                    <button onClick={generateTTS} disabled={!ttsText.trim() || isGeneratingTts} className="bg-gradient-to-r from-teal-500 to-blue-600 hover:from-teal-600 hover:to-blue-700 disabled:opacity-50 text-white px-16 py-5 rounded-2xl font-bold text-xl shadow-2xl transform hover:-translate-y-1 active:scale-95 transition-all w-full md:w-auto">
                      {isGeneratingTts ? 'يتم التوليد...' : 'نطق النص بصوت احترافي'}
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>

          <aside className="lg:col-span-4 space-y-6">
            <div className="bg-slate-800/80 rounded-[40px] border border-slate-700 p-8 shadow-2xl backdrop-blur-xl">
              <h3 className="text-xl font-bold text-white font-cairo mb-8">إعدادات الصوت</h3>

              <div className="space-y-8">
