                    {MOOD_OPTIONS.map(m => (
                      <button key={m.id} onClick={() => setSelectedMood(m)} className={`p-2.5 rounded-xl border text-[10px] font-bold transition-all ${selectedMood.id === m.id ? 'bg-orange-500/10 border-orange-500/50 text-orange-100 shadow-lg' : 'bg-slate-900/40 border-slate-800 text-slate-500'}`}>{m.label}</button>
                    ))}
                  </div>

                  <div className="space-y-6 p-5 bg-slate-900/50 rounded-3xl border border-slate-800/50">
                    <div className="space-y-2">
                       <div className="flex justify-between items-center text-[10px] text-slate-400 font-bold">
                          <span>شدة التأثير</span>
                          <span className="text-orange-400">{effectIntensity}%</span>
                       </div>
                       <input type="range" min="0" max="100" value={effectIntensity} onChange={(e) => setEffectIntensity(parseInt(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-orange-500" />
                    </div>

                    <div className="space-y-2">
                       <div className="flex justify-between items-center text-[10px] text-slate-400 font-bold">
                          <span>طبقة الصوت (Pitch)</span>
                          <span className="text-teal-400">{speechPitch.toFixed(1)}x</span>
                       </div>
                       <input type="range" min="0.5" max="1.5" step="0.1" value={speechPitch} onChange={(e) => setSpeechPitch(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-teal-500" />
                    </div>
                  </div>
                </section>

                <section>
                  <label className="text-xs font-bold text-slate-500 block mb-4 uppercase tracking-widest">اللهجة</label>
                  <div className="grid grid-cols-2 gap-2">
                    {DIALECT_OPTIONS.map(d => (
                      <button key={d.id} onClick={() => setSelectedDialect(d)} className={`p-3 rounded-2xl border text-[11px] font-bold transition-all ${selectedDialect.id === d.id ? 'bg-teal-500/10 border-teal-500/50 text-teal-100 shadow-md' : 'bg-slate-900/40 border-slate-800 text-slate-500'}`}>{d.flag} {d.label}</button>
                    ))}
                  </div>
                </section>
              </div>
            </div>
          </aside>
        </div>
      </div>

      <style>{`
        .font-tajawal { font-family: 'Tajawal', sans-serif; }
        .font-cairo { font-family: 'Cairo', sans-serif; }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 20px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #475569; }
        .scrollbar-hide::-webkit-scrollbar { display: none; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { ConnectionStatus } from './types';
import { encode, decode, decodeAudioData, audioBufferToWav } from './services/audioUtils';
import { Visualizer } from './components/Visualizer';

const LIVE_MODEL = 'gemini-2.5-flash-native-audio-preview-12-2025';
const TTS_MODEL = 'gemini-2.5-flash-preview-tts';

type AppMode = 'live' | 'tts';
type BaseVoice = 'Kore' | 'Puck' | 'Charon' | 'Fenrir' | 'Zephyr';

interface VoicePersona {
  id: string;
  name: string;
  label: string; // e.g. "امرأة"، "رجل"، "طفل"
  base: BaseVoice;
  desc: string;
}

const VOICE_LIST: VoicePersona[] = [
  { id: 'v1', name: 'سارة', label: 'امرأة', base: 'Kore', desc: 'صوت أنثوي ناعم وودود' },
  { id: 'v2', name: 'هند', label: 'امرأة', base: 'Kore', desc: 'صوت أنثوي وقور ورسمي' },
  { id: 'v3', name: 'لينا', label: 'امرأة', base: 'Puck', desc: 'صوت أنثوي حيوي ومرح' },
  { id: 'v4', name: 'عمر', label: 'رجل', base: 'Charon', desc: 'صوت رجولي عميق ورزين' },
  { id: 'v5', name: 'خالد', label: 'رجل', base: 'Fenrir', desc: 'صوت رجولي قوي وجهوري' },
  { id: 'v6', name: 'ياسر', label: 'رجل', base: 'Zephyr', desc: 'صوت رجولي شبابي وعصري' },
  { id: 'v7', name: 'حمزة', label: 'طفل (ولد)', base: 'Zephyr', desc: 'صوت طفل بريء ومتحمس' },
  { id: 'v8', name: 'تالا', label: 'طفل (بنت)', base: 'Puck', desc: 'صوت طفلة صغيرة مرحة' },
];

const STYLE_OPTIONS = [
  { id: 'child', label: 'أطفالي', prompt: 'تحدث بأسلوب طفولي بريء ومرح جداً وكأنك تخاطب أطفالاً: ' },
  { id: 'excited', label: 'حماسي', prompt: 'تحدث بحماس شديد وطاقة متفجرة كالمعلقين الرياضيين: ' },
  { id: 'horror', label: 'رعب', prompt: 'تحدث بنبرة مخيفة وغامضة جداً مع أنفاس ثقيلة وصوت مرعب: ' },
  { id: 'stories', label: 'حكايات/قصص', prompt: 'تحدث بأسلوب الحكواتي المشوق مع تلوين درامي في الإلقاء: ' },
  { id: 'narrator', label: 'راوي', prompt: 'تحدث بأسلوب الراوي الهادئ والعميق الذي يسرد الأحداث بوقار: ' },
  { id: 'announcer', label: 'معلن', prompt: 'تحدث بأسلوب الإعلانات التجارية المندفع والمقنع والجذاب: ' },
  { id: 'documentary', label: 'وثائقي', prompt: 'تحدث بأسلوب الأفلام الوثائقية الرصين والمثقف مع مخارج حروف دقيقة: ' },
  { id: 'damietta', label: 'دمياطي', prompt: 'تحدث بلهجة أهل دمياط المصرية الأصلية مع النغمة المشهورة والمصطلحات الدومياطية المميزة: ' },
  { id: 'natural', label: 'طبيعي', prompt: '' },
];

const DIALECT_OPTIONS = [
  { id: 'fusha', label: 'عربية فصحى', instruction: 'اللغة العربية الفصحى.' },
  { id: 'egyptian', label: 'عامية مصرية', instruction: 'اللهجة المصرية العامية.' },
  { id: 'saudi', label: 'لهجة سعودية', instruction: 'اللهجة السعودية البيضاء.' },
];

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('tts');
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [isGeneratingTts, setIsGeneratingTts] = useState(false);
  const [isPreviewing, setIsPreviewing] = useState<string | null>(null);

  const [ttsText, setTtsText] = useState('');
  const [selectedVoiceId, setSelectedVoiceId] = useState<string>('v1');
  const [pendingVoiceId, setPendingVoiceId] = useState<string>('v1');
  const [selectedStyle, setSelectedStyle] = useState(STYLE_OPTIONS[8]); // Natural
  const [selectedDialect, setSelectedDialect] = useState(DIALECT_OPTIONS[0]);

  // Player States
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [audioProgress, setAudioProgress] = useState(0);
  const [audioDuration, setAudioDuration] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const activeSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  useEffect(() => {
    if (audioRef.current) {
      const el = audioRef.current;
      const updateProgress = () => setAudioProgress(el.currentTime);
      const onEnded = () => setIsPlaying(false);
      const onLoadedMetadata = () => setAudioDuration(el.duration);

      el.addEventListener('timeupdate', updateProgress);
      el.addEventListener('ended', onEnded);
      el.addEventListener('loadedmetadata', onLoadedMetadata);
      return () => {
        el.removeEventListener('timeupdate', updateProgress);
        el.removeEventListener('ended', onEnded);
        el.removeEventListener('loadedmetadata', onLoadedMetadata);
      };
    }
  }, [audioUrl]);

  const stopAllAudio = () => {
    activeSourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
    activeSourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setIsAiSpeaking(false);
    if (audioRef.current) {
      audioRef.current.pause();
      setIsPlaying(false);
    }
  };

  const buildSystemInstruction = () => {
    const voice = VOICE_LIST.find(v => v.id === selectedVoiceId) || VOICE_LIST[0];
    const styleNote = selectedStyle.id !== 'natural' ? `النمط المطلوب: ${selectedStyle.label}.` : "";
    return `أنت هزاع، مساعد ذكي احترافي. تقمص الشخصية التالية: ${voice.name} (${voice.label}). اللهجة المستخدمة: ${selectedDialect.instruction} ${styleNote}`;
  };

  const previewVoice = async (vId: string) => {
    if (isPreviewing) return;
    const voice = VOICE_LIST.find(v => v.id === vId);
    if (!voice) return;
    setIsPreviewing(vId);
    stopAllAudio();
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const greeting = `أهلاً بك في تطبيق هزاع الاحترافي. أنا ${voice.name}، صوت ${voice.label}، جاهز لمساعدتك بنبرتي المميزة.`;
      const response = await ai.models.generateContent({
        model: TTS_MODEL,
        contents: [{ parts: [{ text: greeting }] }],
        config: {
          responseModalalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice.base as any } } },
        },
      });
      const base64 = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64) {
        const ctx = new AudioContext();
        const buffer = await decodeAudioData(decode(base64), ctx, 24000, 1);
        const wavBlob = audioBufferToWav(buffer);
        const url = URL.createObjectURL(wavBlob);
        setAudioUrl(url);
        setIsPlaying(true);
        setTimeout(() => audioRef.current?.play(), 100);
      }
    } catch (err) { console.error(err); } finally { setIsPreviewing(null); }
  };

  const generateTTS = async () => {
    if (!ttsText.trim() || isGeneratingTts) return;
    setIsGeneratingTts(true);
    stopAllAudio();
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const voice = VOICE_LIST.find(v => v.id === selectedVoiceId) || VOICE_LIST[0];
      const prompt = `تقمص شخصية: ${voice.name} (${voice.label}). اللهجة: ${selectedDialect.instruction}. ${selectedStyle.prompt} النص المراد نطقه: "${ttsText}"`;

      const response = await ai.models.generateContent({
        model: TTS_MODEL,
        contents: [{ parts: [{ text: prompt }] }],
        config: {
          responseModalalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice.base as any } } },
        },
      });
      const base64 = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64) {
        const ctx = new AudioContext();
        const buffer = await decodeAudioData(decode(base64), ctx, 24000, 1);
        const wavBlob = audioBufferToWav(buffer);
        const url = URL.createObjectURL(wavBlob);
        setAudioUrl(url);
        setIsPlaying(true);
        setTimeout(() => audioRef.current?.play(), 100);
      }
    } catch (err) { console.error(err); } finally { setIsGeneratingTts(false); }
  };

  const handleStartLive = async () => {
    if (status !== ConnectionStatus.DISCONNECTED) return;
    setStatus(ConnectionStatus.CONNECTING);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      inputAudioContextRef.current = new AudioContext({ sampleRate: 16000 });
      outputAudioContextRef.current = new AudioContext({ sampleRate: 24000 });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const voice = VOICE_LIST.find(v => v.id === selectedVoiceId) || VOICE_LIST[0];

      const sessionPromise = ai.live.connect({
        model: LIVE_MODEL,
        callbacks: {
          onopen: () => setStatus(ConnectionStatus.CONNECTED),
          onmessage: async (message: LiveServerMessage) => {
            const base64 = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64) {
              setIsAiSpeaking(true);
              const ctx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(base64), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.onended = () => {
                activeSourcesRef.current.delete(source);
                if (activeSourcesRef.current.size === 0) setIsAiSpeaking(false);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              activeSourcesRef.current.add(source);
            }
          },
          onerror: () => setStatus(ConnectionStatus.ERROR),
          onclose: () => handleStopLive()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice.base } } },
          systemInstruction: buildSystemInstruction(),
        }
      });
      const source = inputAudioContextRef.current.createMediaStreamSource(stream);
      const scriptProcessor = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);
      scriptProcessor.onaudioprocess = (e) => {
        const input = e.inputBuffer.getChannelData(0);
        const int16 = new Int16Array(input.length);
        for (let i = 0; i < input.length; i++) int16[i] = input[i] * 32768;
        sessionPromise.then(s => s.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } }));
      };
      source.connect(scriptProcessor);
      scriptProcessor.connect(inputAudioContextRef.current.destination);
      sessionRef.current = await sessionPromise;
    } catch (err) { setStatus(ConnectionStatus.ERROR); }
  };

  const handleStopLive = () => {
    if (sessionRef.current) sessionRef.current.close();
    stopAllAudio();
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    setStatus(ConnectionStatus.DISCONNECTED);
  };

