    setIsPreviewing(vId);
    setErrorMessage(null);
    stopAllAudio();
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const greeting = `أهلاً بك في تطبيق هزاع الاحترافي. أنا ${voice.name}، صوت ${voice.gender}، جاهز لمساعدتك بنبرتي المميزة.`;
      const response = await ai.models.generateContent({
        model: TTS_MODEL,
        contents: [{ parts: [{ text: greeting }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice.base as any } } },
        },
      });
      const base64 = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData)?.inlineData?.data;
      if (base64) {
        const ctx = new AudioContext();
        const buffer = await decodeAudioData(decode(base64), ctx, 24000, 1);
        const wavBlob = audioBufferToWav(buffer);
        const url = URL.createObjectURL(wavBlob);
        setAudioUrl(url);
        setIsPlaying(true);
        setTimeout(() => audioRef.current?.play(), 100);
      } else {
        setErrorMessage("فشل في استلام بيانات الصوت للمعاينة.");
      }
    } catch (err) { 
      console.error(err);
      setErrorMessage("حدث خطأ أثناء معاينة الصوت. تأكد من صلاحية مفتاح API.");
    } finally { 
      setIsPreviewing(null); 
    }
  };

  const generateTTS = async () => {
    if (!ttsText.trim() || isGeneratingTts) return;
    setIsGeneratingTts(true);
    setErrorMessage(null);
    stopAllAudio();
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const voice = VOICE_LIST.find(v => v.id === selectedVoiceId) || VOICE_LIST[0];
      const prompt = `تقمص شخصية: ${voice.name} (${voice.gender}). اللهجة: ${selectedDialect.instruction}. ${selectedStyle.prompt} النص المراد نطقه: "${ttsText}"`;

      const response = await ai.models.generateContent({
        model: TTS_MODEL,
        contents: [{ parts: [{ text: prompt }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice.base as any } } },
        },
      });
      const base64 = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData)?.inlineData?.data;
      if (base64) {
        const ctx = new AudioContext();
        const buffer = await decodeAudioData(decode(base64), ctx, 24000, 1);
        const wavBlob = audioBufferToWav(buffer);
        const url = URL.createObjectURL(wavBlob);
        setAudioUrl(url);
        setIsPlaying(true);
        setTimeout(() => audioRef.current?.play(), 100);
      } else {
        setErrorMessage("فشل في استلام بيانات الصوت. حاول مرة أخرى.");
      }
    } catch (err) { 
      console.error(err);
      setErrorMessage("حدث خطأ في الاتصال بواجهة Gemini. يرجى التحقق من اتصالك بالإنترنت.");
    } finally { 
      setIsGeneratingTts(false); 
    }
  };

  const handleStartLive = async () => {
    if (status !== ConnectionStatus.DISCONNECTED) return;
    setStatus(ConnectionStatus.CONNECTING);
    setErrorMessage(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      inputAudioContextRef.current = new AudioContext({ sampleRate: 16000 });
      outputAudioContextRef.current = new AudioContext({ sampleRate: 24000 });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const voice = VOICE_LIST.find(v => v.id === selectedVoiceId) || VOICE_LIST[0];

      const sessionPromise = ai.live.connect({
        model: LIVE_MODEL,
        callbacks: {
          onopen: () => setStatus(ConnectionStatus.CONNECTED),
          onmessage: async (message: LiveServerMessage) => {
            const base64 = message.serverContent?.modelTurn?.parts?.find(p => p.inlineData)?.inlineData?.data;
            if (base64) {
              setIsAiSpeaking(true);
              const ctx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(base64), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.onended = () => {
                activeSourcesRef.current.delete(source);
                if (activeSourcesRef.current.size === 0) setIsAiSpeaking(false);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              activeSourcesRef.current.add(source);
            }
          },
          onerror: (e) => {
            console.error(e);
            setStatus(ConnectionStatus.ERROR);
            setErrorMessage("حدث خطأ في جلسة اللايف.");
          },
          onclose: () => handleStopLive()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voice.base } } },
          systemInstruction: buildSystemInstruction(),
        }
      });
      const source = inputAudioContextRef.current.createMediaStreamSource(stream);
      const scriptProcessor = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);
      scriptProcessor.onaudioprocess = (e) => {
        const input = e.inputBuffer.getChannelData(0);
        const int16 = new Int16Array(input.length);
        for (let i = 0; i < input.length; i++) int16[i] = input[i] * 32768;
        sessionPromise.then(s => s.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } }));
      };
      source.connect(scriptProcessor);
      scriptProcessor.connect(inputAudioContextRef.current.destination);
      sessionRef.current = await sessionPromise;
    } catch (err) { 
      setStatus(ConnectionStatus.ERROR);
      setErrorMessage("تعذر الوصول إلى الميكروفون أو بدء جلسة اللايف.");
    }
  };

  const handleStopLive = () => {
    if (sessionRef.current) sessionRef.current.close();
    stopAllAudio();
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const togglePlayback = () => {
    if (!audioRef.current) return;
    isPlaying ? audioRef.current.pause() : audioRef.current.play();
    setIsPlaying(!isPlaying);
  };

  const seek = (time: number) => { if (audioRef.current) audioRef.current.currentTime = time; };
  const skip = (seconds: number) => { if (audioRef.current) audioRef.current.currentTime += seconds; };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 p-4 md:p-8 font-tajawal">
      <div className="max-w-7xl mx-auto flex flex-col gap-8">

        <header className="flex flex-col md:flex-row items-center justify-between gap-6 bg-slate-800/40 p-6 rounded-[32px] border border-slate-700 shadow-xl backdrop-blur-md">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 bg-gradient-to-br from-teal-400 to-blue-500 rounded-2xl flex items-center justify-center shadow-lg">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
            </div>
            <div>
              <h1 className="text-3xl font-bold font-cairo text-white">هزاع ستوديو <span className="text-teal-400 text-sm font-normal">PRO</span></h1>
              <p className="text-slate-400 text-sm">أقوى استوديو توليد أصوات عربية احترافي</p>
            </div>
          </div>
          <div className="flex bg-slate-900/50 p-1.5 rounded-2xl border border-slate-700">
            <button onClick={() => { setMode('live'); handleStopLive(); }} className={`px-8 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'live' ? 'bg-teal-500 text-white shadow-lg shadow-teal-500/30' : 'text-slate-400 hover:text-slate-200'}`}>لايف</button>
            <button onClick={() => { setMode('tts'); handleStopLive(); }} className={`px-8 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'tts' ? 'bg-teal-500 text-white shadow-lg shadow-teal-500/30' : 'text-slate-400 hover:text-slate-200'}`}>الاستوديو</button>
          </div>
        </header>

        {errorMessage && (
          <div className="bg-red-500/20 border border-red-500/50 p-4 rounded-2xl flex items-center gap-4 animate-shake">
            <svg className="w-6 h-6 text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
            <p className="text-sm font-bold text-red-200">{errorMessage}</p>
            <button onClick={() => setErrorMessage(null)} className="mr-auto text-red-500 hover:text-red-400 font-bold">إغلاق</button>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-8 space-y-6">
            <div className="bg-slate-800/50 rounded-[48px] p-8 md:p-12 border border-slate-700 shadow-2xl min-h-[600px] flex flex-col relative backdrop-blur-md">
              {mode === 'live' ? (
                <div className="flex-1 flex flex-col justify-center">
                  <Visualizer isActive={status === ConnectionStatus.CONNECTED} isSpeaking={isAiSpeaking} />
                  <div className="text-center mt-12">
                    <button onClick={status === ConnectionStatus.CONNECTED ? handleStopLive : handleStartLive} disabled={status === ConnectionStatus.CONNECTING} className={`relative w-40 h-40 rounded-full mx-auto flex items-center justify-center transition-all ${status === ConnectionStatus.CONNECTED ? 'bg-red-500 shadow-[0_0_80px_rgba(239,68,68,0.4)]' : 'bg-teal-500 shadow-[0_0_80px_rgba(20,184,166,0.3)] hover:scale-105'}`}>
                      <div className={`absolute inset-0 rounded-full animate-ping opacity-20 ${status === ConnectionStatus.CONNECTED ? 'bg-red-400' : 'bg-teal-400'}`}></div>
                      <svg className="w-20 h-20 text-white" fill="currentColor" viewBox="0 0 20 20">{status === ConnectionStatus.CONNECTED ? <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1-1H7a1 1 0 00-1 1v6a1 1 0 001 1h1a1 1 0 001-1V7zM14 7a1 1 0 00-1-1h-1a1 1 0 00-1 1v6a1 1 0 001 1h1a1 1 0 001-1V7z"/> : <path d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 006 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z"/>}</svg>
                    </button>
                    <h3 className="text-2xl font-bold mt-10 text-white font-cairo">{status === ConnectionStatus.CONNECTED ? `هزاع يستمع إليك...` : 'ابدأ حواراً فورياً'}</h3>
                  </div>
                </div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="flex items-center justify-between mb-8">
                    <h2 className="text-2xl font-bold font-cairo">تحويل النص إلى نطق احترافي</h2>
                  </div>
                  <textarea value={ttsText} onChange={(e) => setTtsText(e.target.value)} readOnly={isGeneratingTts} placeholder="اكتب النص هنا وسيقوم هزاع بنطقه بالشخصية والنبرة التي تختارها..." className="flex-1 bg-slate-900/60 border border-slate-700/50 rounded-[32px] p-8 text-2xl leading-relaxed text-slate-100 outline-none focus:ring-4 focus:ring-teal-500/10 transition-all resize-none shadow-inner scrollbar-hide mb-6" />

                  {audioUrl && (
                    <div className="mb-8 p-6 bg-slate-900/40 border border-slate-700/50 rounded-[32px] shadow-inner">
                      <div className="flex items-center gap-6 mb-4">
                        <div className="flex items-center gap-2">
                          <button onClick={() => skip(-10)} className="p-2 text-slate-500 hover:text-white transition-colors"><svg className="w-8 h-8" fill="currentColor" viewBox="0 0 20 20"><path d="M8.445 14.832A1 1 0 0010 14V6a1 1 0 00-1.555-.832l-6 4a1 1 0 000 1.664l6 4zM16.445 14.832A1 1 0 0018 14V6a1 1 0 00-1.555-.832l-6 4a1 1 0 000 1.664l6 4z"/></svg></button>
                          <button onClick={togglePlayback} className="w-14 h-14 bg-teal-500 hover:bg-teal-400 rounded-full flex items-center justify-center text-white shadow-xl transition-all active:scale-95">
                            {isPlaying ? <svg className="w-8 h-8" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1-1v4a1 1 0 002 0V8a1 1 0 00-1-1z" clipRule="evenodd"/></svg> : <svg className="w-8 h-8" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd"/></svg>}
                          </button>
                          <button onClick={() => skip(10)} className="p-2 text-slate-500 hover:text-white transition-colors"><svg className="w-8 h-8" fill="currentColor" viewBox="0 0 20 20"><path d="M4.555 5.168A1 1 0 003 6v8a1 1 0 001.555.832l6-4a1 1 0 000-1.664l-6-4zM11.555 5.168A1 1 0 0010 6v8a1 1 0 001.555.832l6-4a1 1 0 000-1.664l-6-4z"/></svg></button>
                        </div>
                        <div className="flex-1 relative pt-1">
                          <input type="range" min="0" max={audioDuration || 0} step="0.01" value={audioProgress} onChange={(e) => seek(parseFloat(e.target.value))} className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-teal-400" />
                          <div className="flex justify-between text-[11px] text-slate-500 mt-2 font-mono font-bold">
                            <span>{Math.floor(audioProgress / 60)}:{Math.floor(audioProgress % 60).toString().padStart(2, '0')}</span>
                            <span>{Math.floor(audioDuration / 60)}:{Math.floor(audioDuration % 60).toString().padStart(2, '0')}</span>
                          </div>
                        </div>
                        <a href={audioUrl} download="hazza_output.wav" className="p-3 bg-slate-800 rounded-2xl text-teal-400 hover:text-teal-300 border border-slate-700 transition-all hover:-translate-y-1"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg></a>
                      </div>
                      <audio ref={audioRef} src={audioUrl} className="hidden" />
                    </div>
                  )}

                  <button onClick={generateTTS} disabled={!ttsText.trim() || isGeneratingTts} className="bg-gradient-to-r from-teal-500 to-blue-600 hover:from-teal-600 hover:to-blue-700 disabled:opacity-50 text-white px-16 py-5 rounded-3xl font-bold text-2xl shadow-2xl transform hover:-translate-y-1 active:scale-95 transition-all w-full flex items-center justify-center gap-4">
                    {isGeneratingTts ? (
                      <>
                        <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                        <span>جارِ التوليد...</span>
                      </>
                    ) : (
                      <>
                        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                        <span>بدء النطق الاحترافي</span>
                      </>
                    )}
                  </button>
                </div>
              )}
            </div>
          </div>

          <aside className="lg:col-span-4 space-y-6">
            <div className="bg-slate-800/80 rounded-[40px] border border-slate-700 p-8 shadow-2xl backdrop-blur-xl flex flex-col gap-8">

              <section>
                <h3 className="text-xl font-bold text-white font-cairo mb-6 flex items-center gap-2">
                  <span className="w-2 h-8 bg-teal-500 rounded-full"></span>
                  اختيار الشخصية
                </h3>
                <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar pr-2">
                  {VOICE_LIST.map(v => (
                    <div key={v.id} className="relative group">
                      <button 
                        onClick={() => setPendingVoiceId(v.id)} 
                        className={`w-full flex items-center justify-between p-4 rounded-2xl border transition-all ${pendingVoiceId === v.id ? 'bg-teal-500/10 border-teal-500/50 text-teal-100 ring-2 ring-teal-500/20' : 'bg-slate-900/40 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                      >
                        <div className="flex items-center gap-4 text-right">
                          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-lg font-black shadow-lg ${selectedVoiceId === v.id ? 'bg-teal-500 text-white' : 'bg-slate-800 text-slate-600'}`}>{v.name[0]}</div>
                          <div>
                            <div className="text-md font-bold flex items-center gap-2">
                              {v.name}
                              <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold ${v.gender === 'امرأة' ? 'bg-pink-500/20 text-pink-400' : v.gender === 'رجل' ? 'bg-blue-500/20 text-blue-400' : 'bg-orange-500/20 text-orange-400'}`}>
                                {v.gender}
                              </span>
                            </div>
                            <div className="text-[11px] opacity-60 font-medium">{v.desc}</div>
                          </div>
                        </div>
                        <button onClick={(e) => { e.stopPropagation(); previewVoice(v.id); }} className="p-2.5 bg-slate-800/80 rounded-xl hover:text-teal-400 shadow-md border border-slate-700/50 transition-colors">
                          {isPreviewing === v.id ? <div className="w-5 h-5 border-2 border-teal-400 border-t-transparent rounded-full animate-spin"></div> : <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z"/></svg>}
                        </button>
                      </button>
                      {pendingVoiceId === v.id && (
                        <button 
                          onClick={() => { setSelectedVoiceId(v.id); stopAllAudio(); }}
                          className="absolute -top-3 left-2 bg-gradient-to-r from-teal-500 to-blue-600 text-white text-[11px] font-bold px-5 py-2 rounded-full shadow-2xl border border-teal-400/50 animate-bounce z-10"
                        >
                          تأكيد الشخصية
                        </button>
                      )}
                    </div>
                  ))}
                </div>
              </section>

              <section>
                <h3 className="text-xl font-bold text-white font-cairo mb-6 flex items-center gap-2">
                  <span className="w-2 h-8 bg-orange-500 rounded-full"></span>
                  اختيار النبرة (Styles)
                </h3>
                <div className="grid grid-cols-2 gap-3">
                  {STYLE_OPTIONS.map(m => (
                    <button key={m.id} onClick={() => setSelectedStyle(m)} className={`p-3 rounded-2xl border text-xs font-bold transition-all ${selectedStyle.id === m.id ? 'bg-orange-500/10 border-orange-500/50 text-orange-100 shadow-lg ring-2 ring-orange-500/20' : 'bg-slate-900/40 border-slate-800 text-slate-500 hover:border-slate-700'}`}>{m.label}</button>
                  ))}
                </div>
              </section>

              <section>
                <h3 className="text-xl font-bold text-white font-cairo mb-6 flex items-center gap-2">
                  <span className="w-2 h-8 bg-blue-500 rounded-full"></span>
                  اللهجة
                </h3>
                <div className="grid grid-cols-1 gap-3">
                  {DIALECT_OPTIONS.map(d => (
                    <button key={d.id} onClick={() => setSelectedDialect(d)} className={`p-4 rounded-2xl border text-sm font-bold transition-all text-right flex items-center justify-between ${selectedDialect.id === d.id ? 'bg-blue-500/10 border-blue-500/50 text-blue-100 shadow-md ring-2 ring-blue-500/20' : 'bg-slate-900/40 border-slate-800 text-slate-500 hover:border-slate-700'}`}>
                      {d.label}
                      {selectedDialect.id === d.id && <svg className="w-5 h-5 text-blue-400" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>}
                    </button>
                  ))}
                </div>
              </section>

            </div>
          </aside>
        </div>
      </div>

      <style>{`
        .font-tajawal { font-family: 'Tajawal', sans-serif; }
        .font-cairo { font-family: 'Cairo', sans-serif; }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 20px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #475569; }
        .scrollbar-hide::-webkit-scrollbar { display: none; }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-5px); }
          75% { transform: translateX(5px); }
        }
        .animate-shake { animation: shake 0.3s ease-in-out; }
      `}</style>
    </div>
  );
};

export default App;
